  async registerHolder(
    nationalId: string, otp: string, deviceId: string,
    publicKey: string, phoneNumber?: string,
  ): Promise<RegisterHolderResponse> {
    const body: Record<string, unknown> = { national_id: nationalId, otp, device_id: deviceId, public_key: publicKey };
    if (phoneNumber) body.phone_number = phoneNumber;
    return this.wrap(() => this.client.post<RegisterHolderResponse>('/auth/holder/register/', body));
  }

  /** POST /token/refresh/ */
  async refreshToken(refreshToken: string): Promise<TokenRefreshResponse> {
    return this.wrap(() =>
      this.client.post<TokenRefreshResponse>('/token/refresh/', { refresh: refreshToken })
    );
  }

  /** GET /users/profile/ */
  async getProfile(accessToken: string): Promise<UserProfileResponse> {
    return this.wrap(() => this.client.get<UserProfileResponse>('/users/profile/', accessToken));
  }

  /** POST /auth/logout/ */
  async logout(accessToken: string): Promise<void> {
    try { await this.client.post('/auth/logout/', undefined, accessToken); }
    catch (e) { /* fire-and-forget */ }
  }

  /** POST /auth/holder/request-otp/ (re-used for PIN reset — same OTP flow) */
  async requestOTPForPINReset(nationalId: string): Promise<RequestOTPResponse> {
    return this.wrap(() =>
      this.client.post<RequestOTPResponse>('/auth/holder/request-otp/', { national_id: nationalId })
    );
  }

  /** POST /auth/holder/reset-pin/ */
  async resetPINWithOTP(
    nationalId: string, otp: string, deviceId: string, publicKey: string,
  ): Promise<{ success: boolean; message: string }> {
    return this.wrap(() =>
      this.client.post('/auth/holder/reset-pin/', { national_id: nationalId, otp, device_id: deviceId, public_key: publicKey })
    );
  }

  /** POST /sync/ */
