export interface NidInitiateResponse { status: string; masked_phone: string; otp_for_testing?: string; }
export interface NidVerifyResponse { verified: boolean; }
export interface NidProfileData {
  fin: string; full_name: string; dob: string; gender: string;
  address: string; phone: string; photo?: string;
}
export interface NidProfileResponse { status: string; data: NidProfileData; }

class NidApi {
  private client: ApiClient;
  constructor() { this.client = new ApiClient(getApiConfig()); }

  // POST /nid/initiate/
  async initiate(fin: string): Promise<NidInitiateResponse> {
    return this.client.post<NidInitiateResponse>('/nid/initiate/', { fin });
  }

  // POST /nid/verify/
  async verifyOtp(fin: string, otp: string): Promise<NidVerifyResponse> {
    return this.client.post<NidVerifyResponse>('/nid/verify/', { fin, otp });
  }

  // GET /nid/get-profile/?fin=
  async getProfile(fin: string): Promise<NidProfileResponse> {
    return this.client.get<NidProfileResponse>(`/nid/get-profile/?fin=${encodeURIComponent(fin)}`);
  }
}

export const nidApi = new NidApi();
