import api from './axios';

// ── Core auth ──────────────────────────────────────────────────────────────────
export const login = (credentials) => api.post('/auth/login/', credentials);
export const logout = () => api.post('/auth/logout/');
export const getMe = () => api.get('/auth/me/');
export const refreshToken = (data) => api.post('/auth/token/refresh/', data);

// ── Password ───────────────────────────────────────────────────────────────────
export const forgotPassword = (data) => api.post('/auth/password/reset/', data);
export const resetPassword = (data) => api.post('/auth/password/reset/confirm/', data);
export const changePassword = (data) => api.post('/auth/password/change/', data);

// ── Holder registration ────────────────────────────────────────────────────────
export const requestHolderOtp = (data) => api.post('/auth/register/request-otp/', data);
export const registerHolder = (data) => api.post('/auth/register/', data);
export const registerWebHolder = (data) => api.post('/auth/register/web/', data);
export const checkHolderStatus = () => api.get('/auth/register/check-status/');
export const getHolderProfile = () => api.get('/auth/profile/');

// ── National ID (Fayda) ────────────────────────────────────────────────────────
export const nidInitiate = (data) => api.post('/national-id/initiate/', data);
export const nidVerifyOtp = (data) => api.post('/national-id/verify-otp/', data);
export const nidGetProfile = () => api.get('/national-id/status/');
export const nidRequestOtp = (data) => api.post('/national-id/request-otp/', data);

// ── DID-based auth ─────────────────────────────────────────────────────────────
export const didAuthChallenge = (data) => api.post('/auth/did/challenge/', data);
export const didAuthRespond = (data) => api.post('/auth/did/respond/', data);

// ── Device management ──────────────────────────────────────────────────────────
export const getDevices = () => api.get('/auth/devices/');
export const deleteDevice = (id) => api.delete(`/auth/devices/${id}/`);
export const logoutAllDevices = () => api.post('/auth/devices/logout-all/');

// ── Organization registration (stays under /organizations/) ───────────────────
export const requestEmailVerification = (data) =>
  api.post('/organizations/register/request-email-verification/', data);
export const verifyEmail = (data) =>
  api.post('/organizations/register/verify-email/', data);
export const createOrgAccount = (data) =>
  api.post('/organizations/register/account-creation/', data);
export const saveOrgDetails = (data) =>
  api.post('/organizations/register/organization-details/', data);
export const saveUseCase = (data) =>
  api.post('/organizations/register/use-case/', data);
export const saveAuthorization = (data) =>
  api.post('/organizations/register/authorization/', data);
export const uploadDocument = (data) =>
  api.post('/organizations/register/upload-document/', data, {
    headers: { 'Content-Type': 'multipart/form-data' },
  });
export const submitApplication = (data) =>
  api.post('/organizations/register/submit-application/', data);
export const getRegistrationStatus = (orgId) =>
  api.get(`/organizations/register/status/${orgId}/`);

import api from './axios';

// ── Credentials in wallet ──────────────────────────────────────────────────────
export const getHolderCredentials = (params) => api.get('/wallet/credentials/', { params });
export const getHolderCredential = (id) => api.get(`/wallet/credentials/${id}/`);
export const renderHolderCredential = (id) => api.get(`/wallet/credentials/${id}/render/`);

// ── My credentials (extended) ──────────────────────────────────────────────────
export const getMyCredentials = (params) => api.get('/wallet/my-credentials/', { params });
export const getMyCredentialStats = () => api.get('/wallet/my-credentials/stats/');
export const getMyCredential = (id) => api.get(`/wallet/my-credentials/${id}/`);
export const downloadMyCredential = (id) => api.get(`/wallet/my-credentials/${id}/download/`);
export const getCredentialVerificationActivity = (id) =>
  api.get(`/wallet/my-credentials/${id}/verification-activity/`);

// ── Credential requests ────────────────────────────────────────────────────────
export const getHolderRequests = (params) => api.get('/wallet/requests/history/', { params });
export const createHolderRequest = (data) => api.post('/wallet/credentials/request/', data);
export const getRequestCatalog = () => api.get('/wallet/request-catalog/');

// ── Sharing management ─────────────────────────────────────────────────────────
export const getShares = (params) => api.get('/wallet/shares/', { params });
export const enableSharing = (data) => api.post('/wallet/shares/enable/', data);
export const disableSharing = (data) => api.post('/wallet/shares/disable/', data);
export const getShareStats = () => api.get('/wallet/shares/stats/');
// Public share access (no auth required)
export const getShare = (token) => api.get(`/share/${token}/`);
export const verifyShare = (token) => api.get(`/share/${token}/verify/`);
export const getShareQr = (token) => api.get(`/share/${token}/qr/`);

// ── Presentations ──────────────────────────────────────────────────────────────
export const getPresentations = (params) => api.get('/wallet/presentations/', { params });
export const createPresentation = (data) => api.post('/wallet/presentations/', data);
export const generateHolderPresentation = (data) =>
  api.post('/wallet/presentations/generate/', data);

// ── Wallets ────────────────────────────────────────────────────────────────────
export const getWallets = () => api.get('/wallet/');
export const createWallet = (data) => api.post('/wallet/create/', data);
export const getWallet = (id) => api.get(`/wallet/${id}/`);

// ── Verification history ───────────────────────────────────────────────────────
export const getHolderVerificationHistory = (params) =>
  api.get('/wallet/verification-history/', { params });

// ── Notifications ──────────────────────────────────────────────────────────────
export const getHolderNotifications = (params) =>
  api.get('/wallet/notifications/', { params });
export const getHolderNotificationCount = () =>
  api.get('/wallet/notifications/unread-count/');
export const markHolderNotificationRead = (id) =>
  api.post(`/wallet/notifications/${id}/mark-read/`);
export const markAllHolderNotificationsRead = () =>
  api.post('/wallet/notifications/mark-all-read/');
export const deleteHolderNotification = (id) =>
  api.delete(`/notifications/${id}/`);

import api from './axios';

// ── Profile ────────────────────────────────────────────────────────────────────
export const getIssuerProfile = () => api.get('/issuer/profile/');
export const updateIssuerProfile = (data) => api.patch('/issuer/profile/', data);

// ── Settings ───────────────────────────────────────────────────────────────────
export const getIssuerSettings = () => api.get('/issuer/settings/');
export const updateIssuerBranding = (data) => api.patch('/issuer/settings/branding/', data);
export const updateIssuerContact = (data) => api.patch('/issuer/settings/contact/', data);
export const getIssuerApiCredentials = () => api.get('/issuer/settings/api-credentials/');
export const regenerateIssuerApiCredentials = () =>
  api.post('/issuer/settings/api-credentials/regenerate/');
export const getIssuerAuditLog = (params) =>
  api.get('/issuer/settings/audit-log/', { params });

// ── Signatories ────────────────────────────────────────────────────────────────
export const getSignatories = () => api.get('/issuer/signatories/');
export const createSignatory = (data) => api.post('/issuer/signatories/', data);
export const updateSignatory = (id, data) => api.patch(`/issuer/signatories/${id}/`, data);
export const deleteSignatory = (id) => api.delete(`/issuer/signatories/${id}/`);
export const setPrimarySignatory = (id) => api.post(`/issuer/signatories/${id}/set-primary/`);

// ── Credential Types (/api/credential-types/) ──────────────────────────────────
export const getCredentialTypes = (params) => api.get('/credential-types/', { params });
export const createCredentialType = (data) => api.post('/credential-types/', data);
export const getCredentialType = (id) => api.get(`/credential-types/${id}/`);
export const updateCredentialType = (id, data) => api.patch(`/credential-types/${id}/`, data);
export const deleteCredentialType = (id) => api.delete(`/credential-types/${id}/`);

// ── Templates (/api/templates/) ────────────────────────────────────────────────
export const getTemplates = (params) => api.get('/templates/', { params });
export const createTemplate = (data) => api.post('/templates/', data);
export const getTemplate = (id) => api.get(`/templates/${id}/`);
export const updateTemplate = (id, data) => api.patch(`/templates/${id}/`, data);
export const deleteTemplate = (id) => api.delete(`/templates/${id}/`);
export const previewTemplate = (id, data) => api.post(`/templates/${id}/preview/`, data);

// ── Template Fields ────────────────────────────────────────────────────────────
export const getTemplateFields = (templateId) => api.get(`/templates/${templateId}/fields/`);
export const createTemplateField = (templateId, data) =>
  api.post(`/templates/${templateId}/fields/`, data);
export const updateTemplateField = (templateId, fieldId, data) =>
  api.patch(`/templates/${templateId}/fields/${fieldId}/`, data);
export const deleteTemplateField = (templateId, fieldId) =>
  api.delete(`/templates/${templateId}/fields/${fieldId}/`);

// ── Issuance (/api/issuance/) ──────────────────────────────────────────────────
export const issueCredential = (templateId, data) =>
  api.post(`/templates/${templateId}/issue/`, data);
export const bulkValidate = (templateId, data) =>
  api.post(`/templates/${templateId}/bulk-validate/`, data, {
    headers: { 'Content-Type': 'multipart/form-data' },
  });
export const bulkIssue = (templateId, data) =>
  api.post(`/templates/${templateId}/bulk-issue/`, data, {
    headers: { 'Content-Type': 'multipart/form-data' },
  });
export const getIssuedCredentials = (params) =>
  api.get('/issuance/credentials/', { params });
export const getIssuedCredential = (id) => api.get(`/issuance/credentials/${id}/`);
export const revokeIssuedCredential = (id, data) =>
  api.post(`/issuance/credentials/${id}/revoke/`, data);
export const suspendIssuedCredential = (id, data) =>
  api.post(`/issuance/credentials/${id}/suspend/`, data);
export const reinstateIssuedCredential = (id) =>
  api.post(`/issuance/credentials/${id}/reinstate/`);
export const expireIssuedCredential = (id) =>
  api.post(`/issuance/credentials/${id}/expire/`);
export const setCredentialExpiry = (id, data) =>
  api.post(`/issuance/credentials/${id}/set-expiry/`, data);

// ── Holder Lookup ──────────────────────────────────────────────────────────────
export const lookupHolder = (params) => api.get('/issuance/holder-lookup/', { params });

// ── Credential Requests from holders ──────────────────────────────────────────
export const getIssuerRequests = (params) => api.get('/issuance/requests/', { params });
export const getIssuerRequest = (id) => api.get(`/issuance/requests/${id}/`);
export const approveRequest = (id, data) =>
  api.post(`/issuance/requests/${id}/approve/`, data);
export const rejectRequest = (id, data) =>
