// ── Response types ──────────────────────────────────────────────────────────

export interface RequestOTPResponse {
  status: string;
  masked_phone: string;
  account_exists?: boolean;
  message?: string;
  otp_for_testing?: string;
}

export interface RegisterHolderResponse {
  success: boolean;
  message: string;
  is_recovery?: boolean;
  user: {
    id: string;
    national_id: string;
    phone_number?: string;
    name: string;
    full_name: string;
    role: string;
    national_id_verified: boolean;
    date_of_birth?: string;
    gender?: string;
    address?: string;
    phone?: string;
    photo?: string;
  };
  identity?: {
    id: string; full_name: string; dob: string;
    gender: string; address: string; photo?: string;
  };
  wallet: { id: string; name: string; device_id?: string; created_at?: string };
  did: string;
  sync_token: string;
  tokens: { access: string; refresh: string };
}

export interface TokenRefreshResponse { access: string; refresh?: string; }

export interface UserProfileResponse {
  id: string; national_id: string; role: string;
  national_id_verified: boolean; is_active: boolean; created_at: string;
  identity: { full_name: string; dob: string; gender: string; address: string; photo?: string };
  did: string;
}

export interface SyncRequest {
  sync_token: string;
  last_sync_timestamp?: string;
  offline_actions?: Array<{ id: string; type: string; data: unknown; timestamp: string }>;
}

export interface SyncResponse {
  processed_actions: Array<{ status: string; action_id: string }>;
  conflicts: unknown[];
  updates: {
    profile_updated: boolean;
    new_credentials: unknown[];
    revoked_credentials: unknown[];
    profile_data?: unknown;
  };
  sync_timestamp: string;
  new_sync_token?: string;
}

// ── AuthApi class ────────────────────────────────────────────────────────────

class AuthApi {
  private readonly client: ApiClient;

  constructor() {
    this.client = new ApiClient(getApiConfig());
  }

  private async wrap<T>(call: () => Promise<T>): Promise<T> {
    try { return await call(); }
    catch (err) { if (err instanceof ApiError) throw err; throw err; }
  }

  /** POST /auth/register/request-otp/ */
  async requestOTP(nationalId: string): Promise<RequestOTPResponse> {
    return this.wrap(() =>
      this.client.post<RequestOTPResponse>('/auth/register/request-otp/', { national_id: nationalId })
    );
  }

  /** POST /auth/register/ */
  async registerHolder(
    nationalId: string, otp: string, deviceId: string,
    publicKey: string, phoneNumber?: string,
  ): Promise<RegisterHolderResponse> {
    const body: Record<string, unknown> = {
      national_id: nationalId, otp, device_id: deviceId, public_key: publicKey,
    };
    if (phoneNumber) body.phone_number = phoneNumber;
    return this.wrap(() => this.client.post<RegisterHolderResponse>('/auth/register/', body));
  }

  /** POST /auth/token/refresh/ */
  async refreshToken(refreshToken: string): Promise<TokenRefreshResponse> {
    return this.wrap(() =>
      this.client.post<TokenRefreshResponse>('/auth/token/refresh/', { refresh: refreshToken })
    );
  }

  /** GET /auth/me/ */
  async getProfile(accessToken: string): Promise<UserProfileResponse> {
    return this.wrap(() => this.client.get<UserProfileResponse>('/auth/me/', accessToken));
  }

  /** POST /auth/logout/ */
  async logout(accessToken: string): Promise<void> {
    try { await this.client.post('/auth/logout/', undefined, accessToken); }
    catch (e) { /* fire-and-forget */ }
  }

  /** POST /auth/register/request-otp/ (re-used for PIN reset) */
  async requestOTPForPINReset(nationalId: string): Promise<RequestOTPResponse> {
    return this.wrap(() =>
      this.client.post<RequestOTPResponse>('/auth/register/request-otp/', { national_id: nationalId })
    );
  }

  /** POST /auth/password/reset/confirm/ */
  async resetPINWithOTP(
    nationalId: string, otp: string, deviceId: string, publicKey: string,
  ): Promise<{ success: boolean; message: string }> {
    return this.wrap(() =>
      this.client.post('/auth/password/reset/confirm/', {
        national_id: nationalId, otp, device_id: deviceId, public_key: publicKey,
      })
    );
  }

  /** POST /auth/profile/ sync */
  async syncData(syncRequest: SyncRequest): Promise<SyncResponse> {
    return this.wrap(() => this.client.post<SyncResponse>('/auth/me/', syncRequest));
  }

  /** GET /wallet/ */
  async getWallets(accessToken: string) {
    return this.wrap(() => this.client.get<unknown[]>('/wallet/', accessToken));
  }

  /** GET /did/ */
  async getDIDs(accessToken: string) {
    return this.wrap(() => this.client.get<unknown[]>('/did/', accessToken));
  }
}

export const authApi = new AuthApi();

