"""
Authentication views for login, password management, and legacy registration
"""
from rest_framework import status, generics
from rest_framework.decorators import api_view, permission_classes
from rest_framework.permissions import AllowAny, IsAuthenticated
from rest_framework.response import Response
from rest_framework_simplejwt.tokens import RefreshToken
from django.contrib.auth import authenticate

from ..serializers import (
    HolderIdentitySerializer,
    UserRegistrationSerializer, UserSerializer, LoginSerializer,
    ForgotPasswordSerializer, ResetPasswordSerializer,
    ChangePasswordSerializer, MobileHolderRegistrationSerializer,
    DIDAuthChallengeSerializer, DIDAuthVerifySerializer
)
from ..services import IdentityService
from ..services.registration_service import check_organization_on_login
from ..services.nid_integration import NationalIDServiceError
from common.rate_limit import rate_limit


# --- SHARED LOGIN ---
@api_view(['POST'])
@permission_classes([AllowAny])
@rate_limit(max_requests=10, window_seconds=60)
def login_view(request):
    serializer = LoginSerializer(data=request.data, context={'request': request})
    serializer.is_valid(raise_exception=True)
    user = authenticate(username=serializer.validated_data['email'], password=serializer.validated_data['password'])

    if not user:
        return Response({"error": "Invalid credentials"}, status=status.HTTP_401_UNAUTHORIZED)

    org_status = check_organization_on_login(user)

    # If it's an issuer and org is not approved, block login
    # Verifiers don't need approval
    if user.role == 'issuer' and org_status.get("organization_status") != 'approved':
        error_code = "PENDING_APPROVAL" if org_status.get("organization_status") == 'pending' else "REJECTED"
        return Response({
            "success": False,
            "error": error_code,
            "message": org_status.get("message")
        }, status=status.HTTP_403_FORBIDDEN)

    refresh = RefreshToken.for_user(user)

    # Safely get full_name from identity if it exists, otherwise use username
    full_name = user.username
    identity_data = None
    try:
        if hasattr(user, 'identity') and user.identity:
            identity = user.identity
            full_name = identity.full_name
            identity_data = HolderIdentitySerializer(identity).data
    except Exception:
        pass

    # Response structure based on role
    response_data = {
        "success": True,
        "user": {
            "id": str(user.id),
            "name": full_name,
            "email": user.email,
            "role": user.role,
            "national_id_verified": user.national_id_verified
        },
        "token": str(refresh.access_token),
        "refresh": str(refresh)
    }

    if user.role == 'holder':
        # Holders get identity/profile data, no organization info
        response_data["user"]["national_id"] = user.national_id
        response_data["user"]["phone_number"] = user.phone_number
        response_data["user"]["identity"] = identity_data
    else:
        # Corporate users (Issuer/Verifier) get organization info
        from organizations.models import Organization
        org = Organization.objects.select_related('organization_type').filter(
            id=user.organization_id or user.pending_organization_id
        ).first()

        response_data["organization"] = {
            "id": str(user.organization_id or user.pending_organization_id),
            "name": org_status.get("organization_name"),
            "status": org_status.get("organization_status"),
            "trust_level": org_status.get("trust_level", "low"),
            "can_issue": org_status.get("can_issue", False),
            "type": org.organization_type.name if org and org.organization_type else None,
        }

    return Response(response_data)


# --- SHARED LOGOUT ---
@api_view(['POST'])
@permission_classes([IsAuthenticated])
def logout_view(request):
    try:
        refresh_token = request.data.get("refresh")
        if refresh_token:
            token = RefreshToken(refresh_token)
            token.blacklist()
        return Response({"success": True, "message": "Successfully logged out."}, status=status.HTTP_200_OK)
    except Exception as e:
        return Response({"error": "Invalid token"}, status=status.HTTP_400_BAD_REQUEST)


# --- LEGACY HOLDER REGISTRATION (Keep for backward compatibility with web) ---
@api_view(['POST'])
@permission_classes([AllowAny])
def register_holder_legacy_view(request):
    """
    Legacy holder registration with email/password
    Kept for backward compatibility with web interface
    """
    serializer = UserRegistrationSerializer(data=request.data)
    if not serializer.is_valid():
        return Response(serializer.errors, status=status.HTTP_400_BAD_REQUEST)

    data = serializer.validated_data
    if not data.get("fin") or not data.get("otp"):
        return Response(
            {"error": "National ID verification required: fin and otp are mandatory"},
            status=status.HTTP_400_BAD_REQUEST,
        )
    ekyc_fields = ['fayda_sub', 'full_name', 'dob', 'gender', 'address', 'photo']
    ekyc_data = {k: data.pop(k) for k in ekyc_fields if k in data}

    try:
        user = IdentityService().register_holder_legacy(
            email=data['email'],
            username=data.get('username'),
            password=data['password'],
            ekyc_data=ekyc_data,
            fin=data.get('fin'),
            otp=data.get('otp')
        )
    except NationalIDServiceError as e:
        return Response({"error": str(e)}, status=e.status_code)
    except ValueError as e:
        return Response({"error": str(e)}, status=status.HTTP_400_BAD_REQUEST)

    refresh = RefreshToken.for_user(user)
    return Response({
        "user": UserSerializer(user, context={'request': request}).data,
        "tokens": {"refresh": str(refresh), "access": str(refresh.access_token)}
    }, status=status.HTTP_201_CREATED)


