"""
Holder Credential Views

API endpoints for holders to manage their credentials.
Includes credential listing, viewing, downloading, and verification tracking.
"""

from rest_framework import viewsets, status
from rest_framework.decorators import action
from rest_framework.response import Response
from rest_framework.permissions import IsAuthenticated
from django.shortcuts import get_object_or_404
from django.http import FileResponse
from django.utils import timezone
from django.db.models import Count
from django.db.models.functions import TruncDate

from credentials.models import Credential, CredentialVerification, CredentialVerificationLog
from credentials.utils.holder_wallet import get_holder_wallet
from credentials.serializers.holder_credential_serializers import (
    HolderCredentialListSerializer,
    HolderCredentialDetailSerializer,
    HolderCredentialDownloadSerializer,
    HolderVerificationActivitySerializer,
)
from identity.models import User, HolderIdentity


class HolderCredentialViewSet(viewsets.ViewSet):
    """
    ViewSet for holder credential operations.

    Endpoints:
    - GET /credentials/ - List all credentials for holder
    - GET /credentials/{id}/ - Get credential detail
    - GET /credentials/{id}/download/ - Download credential as PDF
    - GET /credentials/{id}/verification-activity/ - Get verification activity
    - GET /credentials/stats/ - Get credential statistics
    """

    permission_classes = [IsAuthenticated]

    def list(self, request):
        """
        List all credentials for the authenticated holder.

        Query parameters:
        - status: Filter by status (active, revoked, expired)
        - template_id: Filter by template
        - start_date: Filter by issue date (from)
        - end_date: Filter by issue date (to)
        """
        user = request.user
        wallet_id = request.query_params.get('wallet_id')

        wallet = get_holder_wallet(user, wallet_id)
        if not wallet:
            return Response(
                {'error': 'No active wallet found for user'},
                status=status.HTTP_404_NOT_FOUND,
            )

        queryset = Credential.objects.filter(wallet=wallet).select_related(
            'organization', 'credential_type',
        )

        # Apply filters
        status_filter = request.query_params.get('status')
        if status_filter:
            queryset = queryset.filter(status=status_filter)

        template_id = request.query_params.get('template_id')
        if template_id:
            queryset = queryset.filter(render_metadata__template_id=template_id)

        start_date = request.query_params.get('start_date')
        if start_date:
            queryset = queryset.filter(issued_at__gte=start_date)

        end_date = request.query_params.get('end_date')
        if end_date:
            queryset = queryset.filter(issued_at__lte=end_date)

        # Order by issued date (newest first)
        queryset = queryset.order_by('-issued_at')

        # Serialize
        serializer = HolderCredentialListSerializer(
            queryset,
            many=True,
            context={'request': request}
        )

        return Response({
            'count': queryset.count(),
            'results': serializer.data
        })

    def retrieve(self, request, pk=None):
        """
        Get credential detail for the authenticated holder.
        """
        user = request.user
        wallet = get_holder_wallet(user, request.query_params.get('wallet_id'))
        if not wallet:
            return Response({'error': 'No active wallet found'}, status=status.HTTP_404_NOT_FOUND)

        try:
            credential = Credential.objects.select_related(
                'organization', 'credential_type', 'wallet',
            ).get(id=pk, wallet=wallet)
        except Credential.DoesNotExist:
            return Response(
                {'error': 'Credential not found'},
                status=status.HTTP_404_NOT_FOUND,
            )

        serializer = HolderCredentialDetailSerializer(
            credential,
            context={'request': request}
        )

        return Response(serializer.data)

    @action(detail=True, methods=['get'])
    def download(self, request, pk=None):
        """
        Download credential as PDF.
        """
        user = request.user
        wallet = get_holder_wallet(user, request.query_params.get('wallet_id'))
        if not wallet:
            return Response({'error': 'No active wallet found'}, status=status.HTTP_404_NOT_FOUND)

        try:
            credential = Credential.objects.get(id=pk, wallet=wallet)
        except Credential.DoesNotExist:
            return Response(
                {'error': 'Credential not found'},
                status=status.HTTP_404_NOT_FOUND,
            )

        # Check if PDF exists
        if not credential.render_metadata.get('pdf_url'):
            return Response(
                {'error': 'PDF not available for this credential'},
                status=status.HTTP_400_BAD_REQUEST
            )

        serializer = HolderCredentialDownloadSerializer(credential)
        return Response(serializer.data)

    @action(detail=True, methods=['get'])
    def verification_activity(self, request, pk=None):
        """
        Get verification activity for a credential.

        Returns verification count and history (count only, no verifier identity).
        """
        user = request.user
        wallet = get_holder_wallet(user, request.query_params.get('wallet_id'))
        if not wallet:
            return Response({'error': 'No active wallet found'}, status=status.HTTP_404_NOT_FOUND)

        try:
            credential = Credential.objects.get(id=pk, wallet=wallet)
        except Credential.DoesNotExist:
            return Response(
                {'error': 'Credential not found'},
                status=status.HTTP_404_NOT_FOUND,
            )

        # Get verification tracking
        try:
            verification = credential.verification_tracking
            verification_count = verification.verification_count
            last_verified_at = verification.last_verified_at
        except:
            verification_count = 0
            last_verified_at = None

        # Get verification logs (count by method and status) — single aggregation queries
        logs = CredentialVerificationLog.objects.filter(credential=credential)

        method_counts = logs.values('verification_method').annotate(count=Count('id'))
        verifications_by_method = {row['verification_method']: row['count'] for row in method_counts if row['count'] > 0}

        status_counts = logs.values('verification_status').annotate(count=Count('id'))
        verifications_by_status = {row['verification_status']: row['count'] for row in status_counts if row['count'] > 0}

        # Get daily statistics (last 30 days) — single aggregation query
        thirty_days_ago = timezone.now() - timezone.timedelta(days=30)
        daily_rows = (
            logs.filter(verified_at__gte=thirty_days_ago)
            .annotate(date=TruncDate('verified_at'))
            .values('date')
            .annotate(count=Count('id'))
            .order_by('date')
        )
        daily_stats = {str(row['date']): row['count'] for row in daily_rows}

        return Response({
            'credential_id': str(credential.id),
            'total_verifications': verification_count,
            'last_verified_at': last_verified_at,
            'verifications_by_method': verifications_by_method,
            'verifications_by_status': verifications_by_status,
            'daily_statistics': daily_stats,
        })

    @action(detail=False, methods=['get'])
    def stats(self, request):
        """
        Get credential statistics for the authenticated holder.
        """
        user = request.user
        wallet = get_holder_wallet(user, request.query_params.get('wallet_id'))
        if not wallet:
            return Response(
                {'error': 'No active wallet found for user'},
                status=status.HTTP_404_NOT_FOUND,
            )

        credentials = Credential.objects.filter(wallet=wallet)

        # Single aggregation query for status counts
        status_counts = credentials.values('status').annotate(count=Count('id'))
        status_map = {row['status']: row['count'] for row in status_counts}
        total = sum(status_map.values())

        # Single aggregation query for issuer counts (avoids N+1)
        issuer_counts = credentials.values('organization__name').annotate(count=Count('id')).order_by('-count')
        by_issuer = {row['organization__name']: row['count'] for row in issuer_counts}

        stats = {
            'total_credentials': total,
            'active': status_map.get(Credential.Status.ACTIVE, 0),
            'revoked': status_map.get(Credential.Status.REVOKED, 0),
            'expired': status_map.get(Credential.Status.EXPIRED, 0),
            'by_issuer': by_issuer,
            'by_template': {},
        }

        # Count by template — render_metadata is a JSONField so we still need Python,
        # but we use .values_list to avoid loading full model instances
        for meta in credentials.values_list('render_metadata', flat=True):
            template_name = (meta or {}).get('template_name', 'Unknown') if isinstance(meta, dict) else 'Unknown'
            stats['by_template'][template_name] = stats['by_template'].get(template_name, 0) + 1

        return Response(stats)

    @action(detail=False, methods=['get'])
    def verification_summary(self, request):
        """
        Get verification summary for all holder's credentials.
        """
        user = request.user
        wallet = get_holder_wallet(user, request.query_params.get('wallet_id'))
        if not wallet:
            return Response(
                {'error': 'No active wallet found for user'},
                status=status.HTTP_404_NOT_FOUND,
            )

        credentials = Credential.objects.filter(wallet=wallet)
        credential_ids = list(credentials.values_list('id', flat=True))

        # Single aggregation for total verifications across all holder credentials
        from django.db.models import Sum
        total_agg = CredentialVerification.objects.filter(
            credential_id__in=credential_ids
        ).aggregate(total=Sum('verification_count'))
        total_verifications = total_agg['total'] or 0

        # Single aggregation for method breakdown across all holder credentials
        method_counts = (
            CredentialVerificationLog.objects.filter(credential_id__in=credential_ids)
            .values('verification_method')
            .annotate(count=Count('id'))
        )
        verifications_by_method = {row['verification_method']: row['count'] for row in method_counts if row['count'] > 0}

        return Response({
            'total_verifications': total_verifications,
            'verifications_by_method': verifications_by_method,
            'credentials_count': len(credential_ids),
        })
