@rate_limit(max_requests=3, window_seconds=60, key_func=lambda r: f"otp:{r.data.get('national_id', r.META.get('REMOTE_ADDR', 'unknown'))}")
@require_captcha()
def request_otp_view(request):
    """
    Step 1: Request OTP for holder registration/recovery

    FLOW:
    1. Check if National ID exists locally
       - If YES: Return "Account exists" message (user will provide phone for recovery)
       - If NO: Call National ID Integration API
    2. Generate and send OTP
    3. Return masked phone number

    This endpoint handles both:
    - NEW REGISTRATION: National ID not found locally, calls integration
    - ACCOUNT RECOVERY: National ID found locally, prepares for recovery flow
    """
    national_id = request.data.get('national_id')

    if not national_id:
        return Response({"error": "national_id is required"}, status=status.HTTP_400_BAD_REQUEST)

    # Normalize: strip dashes, spaces, and any non-digit characters
    # Mobile apps often format IDs as '587-302-914-653' while DB stores '587302914653'
    import re
    national_id = re.sub(r'[^\d]', '', str(national_id))

    if not national_id:
        return Response({"error": "national_id must contain digits"}, status=status.HTTP_400_BAD_REQUEST)

    try:
        result = IdentityService().request_otp(national_id)

        # Check if account already exists
        from ..models import User
        existing_user = User.objects.filter(national_id=national_id).first()
        payload = {
            "status": "otp_sent",
            "masked_phone": result['masked_phone'],
            "account_exists": existing_user is not None,
            "message": "Account found. Please provide your phone number for verification." if existing_user else "OTP sent to your registered phone number.",
        }
        return Response(payload)
    except NationalIDServiceError as e:
        return Response({
            "error": str(e),
            "error_code": "NID_SERVICE_ERROR"
        }, status=e.status_code)
    except ValueError as e:
        return Response({
            "error": str(e),
            "error_code": "VALIDATION_ERROR"
        }, status=status.HTTP_400_BAD_REQUEST)


