          <Button size="sm" onClick={() => { setShareModal(true); }} disabled={credential.status !== 'active'}>
            <Share2 className="h-4 w-4" />Share
          </Button>
          {qrUrl && (
            <Button size="sm" variant="outline" onClick={() => setQrModal(true)}>
              <QrCode className="h-4 w-4" />QR Code
            </Button>
          )}
        </div>
      </div>

      {/* Claims */}
      {claims.length > 0 && (
        <div className="rounded-xl border border-border bg-card p-5">
          <h2 className="font-semibold text-foreground mb-4">Credential Claims</h2>
          <dl className="divide-y divide-border">
            {claims.map((c) => (
              <div key={c.key} className="flex items-start justify-between py-3">
                <dt className="text-sm text-muted-foreground">{c.label}</dt>
                <dd className="text-sm font-medium text-foreground max-w-xs text-right">{c.value}</dd>
              </div>
            ))}
          </dl>
        </div>
      )}

      {/* Share Modal */}
      <Modal open={shareModal} onClose={() => { setShareModal(false); setShareResult(null); }} title="Share Credential">
        {!shareResult ? (
          <div className="space-y-4">
            <p className="text-sm text-muted-foreground">Choose how long the share link stays active.</p>
            <div className="grid grid-cols-3 gap-3">
              {[{ h: 1, label: '1 Hour' }, { h: 24, label: '24 Hours' }, { h: 168, label: '7 Days' }].map((opt) => (
                <Button key={opt.h} variant="outline" loading={shareLoading} onClick={() => handleShare(opt.h)}>{opt.label}</Button>
              ))}
            </div>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="rounded-lg bg-muted p-3">
              <p className="text-xs text-muted-foreground mb-1">Share Link</p>
              <p className="font-mono text-xs break-all text-foreground">{`${window.location.origin}/verify/${shareResult.token || shareResult.share_token}`}</p>
            </div>
            {qrUrl && <img src={qrUrl} alt="QR Code" className="mx-auto rounded-lg w-48 h-48" />}
            <Button className="w-full" onClick={() => {
              navigator.clipboard.writeText(`${window.location.origin}/verify/${shareResult.token || shareResult.share_token}`);
              toast.success('Link copied!');
            }}>Copy Link</Button>
          </div>
        )}
      </Modal>

      <Modal open={qrModal} onClose={() => setQrModal(false)} title="QR Code">
        {qrUrl && <img src={qrUrl} alt="QR Code" className="mx-auto w-64 h-64" />}
      </Modal>
    </div>
  );
}
