import { useEffect, useState, useCallback } from 'react';
import { Link } from 'react-router-dom';
import {
  CreditCard, Share2, ClipboardList, ArrowRight, ShieldCheck,
  Bell, Fingerprint, Activity, Plus, RefreshCw, Key,
} from 'lucide-react';
import {
  getHolderCredentials,
  getHolderNotifications,
  getHolderNotificationCount,
} from '../../api/holder';
import { StatusBadge } from '../../components/common/Badge';
import { formatDate, formatRelative } from '../../utils/formatDate';
import useAuthStore from '../../store/authStore';
import { CardSkeleton } from '../../components/common/SkeletonLoader';

export default function HolderDashboard() {
  const { user } = useAuthStore();
  const [credentials, setCredentials] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  const load = useCallback(async (showRefresh = false) => {
    if (showRefresh) setRefreshing(true);
    try {
      const [credsRes, notifRes, countRes] = await Promise.allSettled([
        getHolderCredentials({ page_size: 6 }),
        getHolderNotifications({ limit: 5 }),
        getHolderNotificationCount(),
      ]);
      if (credsRes.status === 'fulfilled') {
        const d = credsRes.value.data;
        setCredentials(d?.results || d || []);
      }
      if (notifRes.status === 'fulfilled') {
        setNotifications(notifRes.value.data?.results || notifRes.value.data || []);
      }
      if (countRes.status === 'fulfilled') {
        setUnreadCount(countRes.value.data?.unread_count || 0);
      }
    } catch { }
    setLoading(false);
    setRefreshing(false);
  }, []);

  useEffect(() => { load(); }, [load]);

  const active = credentials.filter((c) => c.status === 'active').length;
  const expired = credentials.filter((c) => c.status === 'expired').length;
  const revoked = credentials.filter((c) => c.status === 'revoked').length;

  const identity = user?.identity;
  const displayName = identity?.full_name
    || (user?.first_name ? `${user.first_name} ${user.last_name || ''}`.trim() : null)
    || user?.email?.split('@')[0]
    || 'Holder';

  const did = user?.did || identity?.did || '';

  const statCards = [
    { label: 'Total', value: credentials.length, color: 'text-blue-600', bg: 'bg-blue-50 dark:bg-blue-900/20', icon: CreditCard },
    { label: 'Active', value: active, color: 'text-green-600', bg: 'bg-green-50 dark:bg-green-900/20', icon: ShieldCheck },
    { label: 'Expired', value: expired, color: 'text-yellow-600', bg: 'bg-yellow-50 dark:bg-yellow-900/20', icon: ClipboardList },
    { label: 'Revoked', value: revoked, color: 'text-red-600', bg: 'bg-red-50 dark:bg-red-900/20', icon: Activity },
  ];

  const quickActions = [
    { to: '/holder/credentials/request', icon: Plus, label: 'Request Credential', desc: 'Ask an issuer' },
    { to: '/holder/credentials', icon: ShieldCheck, label: 'My Credentials', desc: 'View & manage all' },
    { to: '/holder/shares', icon: Share2, label: 'Shared Links', desc: 'Manage shares' },
    { to: '/holder/presentations', icon: Fingerprint, label: 'Presentations', desc: 'Verifiable proofs' },
  ];

  return (
    <div className="space-y-6">
      {/* Header row */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">
            Welcome, {displayName.split(' ')[0]}!
          </h1>
          <p className="text-muted-foreground text-sm mt-0.5">Your digital credential wallet.</p>
        </div>
        <div className="flex items-center gap-2">
          <button
            onClick={() => load(true)}
            disabled={refreshing}
            className="rounded-lg p-2 hover:bg-muted/50 transition-colors text-muted-foreground disabled:opacity-40"
            title="Refresh"
          >
            <RefreshCw className={`h-4 w-4 ${refreshing ? 'animate-spin' : ''}`} />
          </button>
          <Link
            to="/holder/notifications"
            className="relative rounded-lg p-2 hover:bg-muted/50 transition-colors text-muted-foreground"
          >
            <Bell className="h-4 w-4" />
            {unreadCount > 0 && (
              <span className="absolute -top-0.5 -right-0.5 flex h-4 w-4 items-center justify-center rounded-full bg-primary text-[10px] font-bold text-primary-foreground">
                {unreadCount > 9 ? '9+' : unreadCount}
              </span>
            )}
          </Link>
        </div>
      </div>

      {/* Identity card */}
      <div className="rounded-2xl bg-gradient-to-br from-primary via-primary/90 to-primary/70 p-5 text-primary-foreground shadow-md">
        <div className="flex items-start justify-between mb-3">
          <div>
            <p className="text-primary-foreground/60 text-[10px] font-semibold uppercase tracking-widest">
              Digital Identity
            </p>
            <h2 className="text-lg font-bold mt-0.5">{displayName}</h2>
            {user?.national_id && (
              <p className="text-primary-foreground/75 text-sm mt-0.5">
                NID: {user.national_id}
              </p>
            )}
          </div>
          <div className="rounded-xl bg-primary-foreground/15 p-2.5">
            <Fingerprint className="h-6 w-6" />
          </div>
        </div>

        {did && (
          <div className="rounded-lg bg-primary-foreground/10 px-3 py-2 mb-3">
            <p className="text-[10px] text-primary-foreground/50 uppercase tracking-wide mb-0.5">DID</p>
            <p className="font-mono text-xs text-primary-foreground/85 truncate">{did}</p>
          </div>
        )}

        <div className="flex items-center gap-2">
          <div className="h-2 w-2 rounded-full bg-green-400 animate-pulse" />
          <p className="text-xs text-primary-foreground/75">
            {user?.national_id_verified ? 'Identity Verified · ' : 'Wallet Active · '}
            {credentials.length} credential{credentials.length !== 1 ? 's' : ''}
          </p>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        {statCards.map((s) => (
          <div key={s.label} className="rounded-xl border border-border bg-card p-4">
            <div className="flex items-center justify-between mb-2">
              <span className="text-xs text-muted-foreground">{s.label}</span>
              <div className={`rounded-lg p-1.5 ${s.bg}`}>
                <s.icon className={`h-3.5 w-3.5 ${s.color}`} />
              </div>
            </div>
            <p className="text-2xl font-bold text-foreground">{loading ? '—' : s.value}</p>
          </div>
        ))}
      </div>

      {/* Quick actions */}
      <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-3">
        {quickActions.map((a) => (
          <Link
            key={a.to}
            to={a.to}
            className="flex items-center gap-3 rounded-xl border border-border bg-card p-4 hover:bg-muted/30 hover:shadow-sm transition-all group"
          >
            <div className="rounded-xl bg-primary/10 p-2.5 shrink-0 group-hover:bg-primary/20 transition-colors">
              <a.icon className="h-4 w-4 text-primary" />
            </div>
            <div className="min-w-0">
              <p className="font-medium text-foreground text-sm">{a.label}</p>
              <p className="text-xs text-muted-foreground">{a.desc}</p>
            </div>
          </Link>
        ))}
      </div>

      {/* Two-column: credentials + notifications */}
      <div className="grid lg:grid-cols-5 gap-5">
        {/* Recent credentials */}
        <div className="lg:col-span-3 rounded-xl border border-border bg-card overflow-hidden">
          <div className="flex items-center justify-between px-4 py-3.5 border-b border-border">
            <h2 className="font-semibold text-foreground text-sm">Recent Credentials</h2>
            <Link to="/holder/credentials" className="text-xs text-primary hover:underline">
              View all →
            </Link>
          </div>
          <div className="divide-y divide-border">
            {loading ? (
              <div className="p-4 space-y-3">
                {[1, 2, 3].map((i) => <CardSkeleton key={i} />)}
              </div>
            ) : credentials.length === 0 ? (
              <div className="py-10 text-center text-sm text-muted-foreground">
                No credentials yet.{' '}
                <Link to="/holder/credentials/request" className="text-primary hover:underline">
                  Request one →
                </Link>
              </div>
            ) : (
              credentials.slice(0, 6).map((c) => (
                <Link
                  key={c.id}
                  to={`/holder/credentials/${c.id}`}
                  className="flex items-center justify-between p-3.5 hover:bg-muted/30 transition-colors"
                >
                  <div className="flex items-center gap-3 min-w-0">
                    <div className="rounded-lg bg-primary/10 p-2 shrink-0">
                      <CreditCard className="h-3.5 w-3.5 text-primary" />
                    </div>
                    <div className="min-w-0">
                      <p className="font-medium text-sm text-foreground truncate">
                        {c.credential_type_name || c.type || 'Credential'}
                      </p>
                      <p className="text-xs text-muted-foreground truncate">
                        {c.issuer_name || '—'} · {formatDate(c.issued_at || c.issuanceDate)}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 shrink-0 ml-2">
                    <StatusBadge status={c.status} />
                    <ArrowRight className="h-3.5 w-3.5 text-muted-foreground" />
                  </div>
                </Link>
              ))
            )}
          </div>
        </div>

        {/* Notifications */}
        <div className="lg:col-span-2 rounded-xl border border-border bg-card overflow-hidden">
          <div className="flex items-center justify-between px-4 py-3.5 border-b border-border">
            <div className="flex items-center gap-2">
              <h2 className="font-semibold text-foreground text-sm">Notifications</h2>
              {unreadCount > 0 && (
                <span className="flex h-5 min-w-5 items-center justify-center rounded-full bg-primary px-1 text-[10px] font-bold text-primary-foreground">
                  {unreadCount}
                </span>
              )}
            </div>
            <Link to="/holder/notifications" className="text-xs text-primary hover:underline">
              View all →
            </Link>
          </div>
          <div className="divide-y divide-border">
            {loading ? (
              <div className="p-4 space-y-3">
                {[1, 2].map((i) => <CardSkeleton key={i} />)}
              </div>
            ) : notifications.length === 0 ? (
              <div className="py-10 text-center">
                <Bell className="h-6 w-6 text-muted-foreground mx-auto mb-2" />
                <p className="text-sm text-muted-foreground">No notifications</p>
              </div>
            ) : (
              notifications.map((n) => {
                const notif = n.notification || n;
                const isUnread = !n.is_read && n.status !== 'read';
                return (
                  <div
                    key={n.id}
                    className={`flex items-start gap-3 p-3.5 ${isUnread ? 'bg-primary/5' : ''}`}
                  >
                    <div className={`mt-1.5 h-2 w-2 shrink-0 rounded-full ${isUnread ? 'bg-primary' : 'bg-transparent'}`} />
                    <div className="min-w-0 flex-1">
                      <p className="text-sm font-medium text-foreground truncate">
                        {notif.title || notif.message || 'Notification'}
                      </p>
                      <p className="text-xs text-muted-foreground mt-0.5">
                        {formatRelative(notif.created_at || n.created_at)}
                      </p>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </div>
      </div>

      {/* Bottom links */}
      <div className="grid sm:grid-cols-2 gap-4">
        {[
          {
            to: '/holder/requests',
            icon: ClipboardList,
            label: 'Credential Requests',
            desc: 'Track pending & approved requests',
          },
          {
            to: '/holder/verification-history',
            icon: Activity,
            label: 'Verification History',
            desc: 'See when your credentials were verified',
          },
        ].map((a) => (
          <Link
            key={a.to}
            to={a.to}
            className="flex items-center gap-4 rounded-xl border border-border bg-card p-4 hover:bg-muted/30 transition-colors group"
          >
            <div className="rounded-xl bg-muted p-3 shrink-0">
              <a.icon className="h-5 w-5 text-muted-foreground" />
            </div>
            <div className="flex-1">
              <p className="font-medium text-foreground text-sm">{a.label}</p>
              <p className="text-xs text-muted-foreground">{a.desc}</p>
            </div>
            <ArrowRight className="h-4 w-4 text-muted-foreground group-hover:text-foreground transition-colors" />
          </Link>
        ))}
      </div>
    </div>
  );
}

import { useEffect, useState, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { Plus, CreditCard, Filter, ShieldCheck, AlertTriangle, XCircle } from 'lucide-react';
import { getHolderCredentials } from '../../api/holder';
import { StatusBadge } from '../../components/common/Badge';
import Button from '../../components/common/Button';
import SearchInput from '../../components/common/SearchInput';
import Pagination from '../../components/common/Pagination';
import EmptyState from '../../components/common/EmptyState';
import { CardSkeleton } from '../../components/common/SkeletonLoader';
import { formatDate } from '../../utils/formatDate';
import useDebounce from '../../hooks/useDebounce';

const STATUS_TABS = [
  { key: '', label: 'All', icon: CreditCard },
  { key: 'active', label: 'Active', icon: ShieldCheck },
  { key: 'expired', label: 'Expired', icon: AlertTriangle },
  { key: 'revoked', label: 'Revoked', icon: XCircle },
];

const STATUS_COLORS = {
  active: 'from-green-500 to-emerald-600',
  revoked: 'from-red-500 to-rose-600',
  expired: 'from-yellow-500 to-amber-600',
  default: 'from-primary to-primary/80',
};

export default function CredentialsPage() {
  const [credentials, setCredentials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalCount, setTotalCount] = useState(0);
  const debouncedSearch = useDebounce(search);

  const load = useCallback(() => {
    setLoading(true);
    const params = { page, page_size: 12 };
    if (debouncedSearch) params.search = debouncedSearch;
    if (statusFilter) params.status = statusFilter;

    getHolderCredentials(params)
      .then((r) => {
        const data = r.data;
        const results = data?.results || data || [];
        const count = data?.count || results.length;
        setCredentials(results);
        setTotalCount(count);
        setTotalPages(Math.ceil(count / 12));
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [debouncedSearch, statusFilter, page]);

  useEffect(() => { load(); }, [load]);

  const handleTabChange = (key) => {
    setStatusFilter(key);
    setPage(1);
  };

  const handleSearch = (v) => {
    setSearch(v);
    setPage(1);
  };

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">My Credentials</h1>
          {!loading && (
            <p className="text-sm text-muted-foreground mt-0.5">
              {totalCount} credential{totalCount !== 1 ? 's' : ''}
              {statusFilter ? ` (${statusFilter})` : ''}
            </p>
          )}
        </div>
        <Link to="/holder/credentials/request">
          <Button size="sm">
            <Plus className="h-4 w-4" />Request
          </Button>
        </Link>
      </div>

      {/* Search */}
      <SearchInput value={search} onChange={handleSearch} placeholder="Search by type, issuer…" />

      {/* Status tabs */}
      <div className="flex gap-1 rounded-xl bg-muted/50 p-1 w-fit">
        {STATUS_TABS.map((t) => (
          <button
            key={t.key}
            onClick={() => handleTabChange(t.key)}
            className={`flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-sm font-medium transition-all ${
              statusFilter === t.key
                ? 'bg-card text-foreground shadow-sm'
                : 'text-muted-foreground hover:text-foreground'
            }`}
          >
            <t.icon className="h-3.5 w-3.5" />
            {t.label}
          </button>
        ))}
      </div>

      {/* Grid */}
      {loading ? (
        <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {Array.from({ length: 6 }).map((_, i) => (
            <div key={i} className="rounded-xl border border-border bg-card p-5 h-36">
              <CardSkeleton />
            </div>
          ))}
        </div>
      ) : credentials.length === 0 ? (
        <EmptyState
          icon={CreditCard}
          title={search ? 'No credentials match your search' : statusFilter ? `No ${statusFilter} credentials` : 'No credentials yet'}
          description={
            search
              ? 'Try a different search term.'
              : 'Request a credential from an issuer to get started.'
          }
          action={
            !search && (
              <Link to="/holder/credentials/request">
                <Button size="sm"><Plus className="h-4 w-4" />Request Credential</Button>
              </Link>
            )
          }
        />
      ) : (
        <>
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {credentials.map((c) => {
              const gradient = STATUS_COLORS[c.status] || STATUS_COLORS.default;
              return (
                <Link
                  key={c.id}
                  to={`/holder/credentials/${c.id}`}
                  className="rounded-xl border border-border bg-card overflow-hidden hover:shadow-md transition-all group"
                >
                  {/* Colored top strip */}
                  <div className={`h-1.5 bg-gradient-to-r ${gradient}`} />
                  <div className="p-5">
                    <div className="flex items-start justify-between mb-3">
                      <div className="rounded-xl bg-primary/10 p-2.5 group-hover:bg-primary/20 transition-colors">
                        <CreditCard className="h-4 w-4 text-primary" />
                      </div>
                      <StatusBadge status={c.status} />
                    </div>
                    <h3 className="font-semibold text-foreground text-sm mb-1 truncate">
                      {c.credential_type_name || c.type || 'Credential'}
                    </h3>
                    <p className="text-xs text-muted-foreground mb-3 truncate">
                      Issued by {c.issuer_name || '—'}
                    </p>
                    <div className="flex items-center justify-between text-xs text-muted-foreground">
                      <span>Issued: {formatDate(c.issued_at || c.issuanceDate)}</span>
                      {c.expiration_date && (
                        <span className={c.status === 'expired' ? 'text-yellow-600 font-medium' : ''}>
                          Exp: {formatDate(c.expiration_date)}
                        </span>
                      )}
                    </div>
                  </div>
                </Link>
              );
            })}
          </div>
          {totalPages > 1 && (
            <Pagination page={page} totalPages={totalPages} onPageChange={setPage} />
          )}
        </>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import {
  Share2, ArrowLeft, QrCode, Copy, Clock, Building2,
  ShieldCheck, Activity, ExternalLink, ChevronDown, ChevronUp,
} from 'lucide-react';
import { getHolderCredential, createShare, getCredentialVerificationActivity } from '../../api/holder';
import { StatusBadge } from '../../components/common/Badge';
import Button from '../../components/common/Button';
import Modal from '../../components/common/Modal';
import { FullPageSpinner } from '../../components/common/Spinner';
import { formatDate, formatDateTime } from '../../utils/formatDate';
import { flattenClaims } from '../../utils/claimsUtils';
import toast from 'react-hot-toast';
import QRCode from 'qrcode';

function InfoRow({ label, value, mono = false }) {
  if (!value) return null;
  return (
    <div className="flex items-start justify-between py-3 gap-4">
      <dt className="text-sm text-muted-foreground shrink-0">{label}</dt>
      <dd className={`text-sm font-medium text-foreground text-right ${mono ? 'font-mono text-xs break-all' : ''}`}>
        {value}
      </dd>
    </div>
  );
}

export default function CredentialDetailPage() {
  const { id } = useParams();
  const [credential, setCredential] = useState(null);
  const [activity, setActivity] = useState(null);
  const [loading, setLoading] = useState(true);
  const [shareModal, setShareModal] = useState(false);
  const [qrModal, setQrModal] = useState(false);
  const [qrUrl, setQrUrl] = useState('');
  const [shareLoading, setShareLoading] = useState(false);
  const [shareResult, setShareResult] = useState(null);
  const [showRaw, setShowRaw] = useState(false);

  useEffect(() => {
    setLoading(true);
    Promise.allSettled([
      getHolderCredential(id),
      getCredentialVerificationActivity(id).catch(() => null),
    ]).then(([credRes, actRes]) => {
      if (credRes.status === 'fulfilled') setCredential(credRes.value.data);
      if (actRes.status === 'fulfilled' && actRes.value) setActivity(actRes.value.data);
    }).catch(() => toast.error('Failed to load credential'))
      .finally(() => setLoading(false));
  }, [id]);

  const handleShare = async (expiryHours = 24) => {
    setShareLoading(true);
    try {
      const res = await createShare(id, { expiry_hours: expiryHours });
      setShareResult(res.data);
      const token = res.data.token || res.data.share_token;
      const url = `${window.location.origin}/verify/${token}`;
      const qr = await QRCode.toDataURL(url, { width: 300, margin: 2 });
      setQrUrl(qr);
      toast.success('Share link created');
    } catch (err) {
      toast.error(err.response?.data?.detail || err.response?.data?.error || 'Failed to create share link');
    } finally {
      setShareLoading(false);
    }
  };

  const copyLink = (token) => {
    navigator.clipboard.writeText(`${window.location.origin}/verify/${token}`);
    toast.success('Link copied to clipboard');
  };

  if (loading) return <FullPageSpinner />;
  if (!credential) return (
    <div className="text-center py-20">
      <p className="text-muted-foreground">Credential not found.</p>
      <Link to="/holder/credentials" className="mt-4 inline-block text-primary hover:underline text-sm">
        ← Back to credentials
      </Link>
    </div>
  );

  const claims = flattenClaims(
    credential.credential_data?.credentialSubject
    || credential.credentialSubject
    || credential.claims
    || {}
  );
  const shareToken = shareResult?.token || shareResult?.share_token;
  const shareUrl = shareToken ? `${window.location.origin}/verify/${shareToken}` : '';

  return (
    <div className="max-w-2xl mx-auto space-y-5">
      {/* Back nav */}
      <div className="flex items-center gap-2">
        <Link to="/holder/credentials">
          <Button variant="ghost" size="sm" className="gap-1.5">
            <ArrowLeft className="h-3.5 w-3.5" />Back
          </Button>
        </Link>
      </div>

      {/* Main credential card */}
      <div className="rounded-2xl border border-border bg-card overflow-hidden">
        {/* Gradient header */}
        <div className={`h-2 ${credential.status === 'active' ? 'bg-gradient-to-r from-green-500 to-emerald-600' : credential.status === 'revoked' ? 'bg-gradient-to-r from-red-500 to-rose-600' : 'bg-gradient-to-r from-yellow-500 to-amber-600'}`} />
        <div className="p-6">
          <div className="flex items-start justify-between mb-5">
            <div>
              <h1 className="text-xl font-bold text-foreground">
                {credential.credential_type_name || credential.type || 'Credential'}
              </h1>
              <div className="flex items-center gap-1.5 mt-1">
                <Building2 className="h-3.5 w-3.5 text-muted-foreground" />
                <p className="text-sm text-muted-foreground">
                  {credential.issuer_name || credential.organization_name || '—'}
                </p>
              </div>
            </div>
            <StatusBadge status={credential.status} />
          </div>

          <dl className="divide-y divide-border">
            <InfoRow label="Issued" value={formatDate(credential.issued_at || credential.issuanceDate)} />
            <InfoRow label="Expires" value={credential.expiration_date ? formatDate(credential.expiration_date) : 'No expiry'} />
            <InfoRow label="Credential ID" value={credential.credential_uuid || credential.credential_id || credential.id} mono />
            {credential.holder_did && <InfoRow label="Holder DID" value={credential.holder_did} mono />}
            {credential.issuer_did && <InfoRow label="Issuer DID" value={credential.issuer_did} mono />}
          </dl>

          {/* Actions */}
          <div className="flex gap-2 mt-5">
            <Button
              size="sm"
              onClick={() => setShareModal(true)}
              disabled={credential.status !== 'active'}
            >
              <Share2 className="h-3.5 w-3.5" />Share
            </Button>
            {qrUrl && (
              <Button size="sm" variant="outline" onClick={() => setQrModal(true)}>
                <QrCode className="h-3.5 w-3.5" />QR Code
              </Button>
            )}
            {credential.verification_url && (
              <a
                href={credential.verification_url}
                target="_blank"
                rel="noopener noreferrer"
                className="inline-flex items-center gap-1.5 rounded-lg border border-border px-3 py-1.5 text-sm font-medium text-muted-foreground hover:text-foreground hover:bg-muted/50 transition-colors"
              >
                <ExternalLink className="h-3.5 w-3.5" />Verify
              </a>
            )}
          </div>
        </div>
      </div>

      {/* Claims */}
      {claims.length > 0 && (
        <div className="rounded-xl border border-border bg-card p-5">
          <h2 className="font-semibold text-foreground mb-1">Credential Claims</h2>
          <p className="text-xs text-muted-foreground mb-4">
            Verified attributes included in this credential.
          </p>
          <dl className="divide-y divide-border">
            {claims.map((c) => (
              <div key={c.key} className="flex items-start justify-between py-3 gap-4">
                <dt className="text-sm text-muted-foreground capitalize shrink-0">{c.label}</dt>
                <dd className="text-sm font-medium text-foreground text-right max-w-xs break-words">
                  {c.value}
                </dd>
              </div>
            ))}
          </dl>
        </div>
      )}

      {/* Verification activity */}
      {activity && (
        <div className="rounded-xl border border-border bg-card p-5">
          <div className="flex items-center gap-2 mb-4">
            <Activity className="h-4 w-4 text-muted-foreground" />
            <h2 className="font-semibold text-foreground">Verification Activity</h2>
          </div>
          <div className="grid grid-cols-3 gap-4 mb-4">
            <div className="rounded-lg bg-muted/50 p-3 text-center">
              <p className="text-2xl font-bold text-foreground">{activity.total_verifications || 0}</p>
              <p className="text-xs text-muted-foreground mt-0.5">Total</p>
            </div>
            {activity.last_verified_at && (
              <div className="col-span-2 rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground mb-1">Last verified</p>
                <p className="text-sm font-medium text-foreground">{formatDateTime(activity.last_verified_at)}</p>
              </div>
            )}
          </div>
          {activity.verifications_by_method && Object.keys(activity.verifications_by_method).length > 0 && (
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-wide mb-2">By method</p>
              <div className="flex flex-wrap gap-2">
                {Object.entries(activity.verifications_by_method).map(([method, count]) => (
                  <span
                    key={method}
                    className="inline-flex items-center gap-1 rounded-full bg-muted px-2.5 py-0.5 text-xs font-medium text-muted-foreground"
                  >
                    {method}: {count}
                  </span>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Raw JSON (collapsible) */}
      {(credential.credential_data || credential.signed_jwt) && (
        <div className="rounded-xl border border-border bg-card overflow-hidden">
          <button
            onClick={() => setShowRaw(!showRaw)}
            className="w-full flex items-center justify-between p-4 text-sm font-medium text-foreground hover:bg-muted/30 transition-colors"
          >
            <span>Raw Credential Data</span>
            {showRaw ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
          </button>
          {showRaw && (
            <pre className="p-4 text-xs text-muted-foreground bg-muted/30 overflow-auto max-h-80 border-t border-border">
              {JSON.stringify(credential.credential_data || { jwt: credential.signed_jwt }, null, 2)}
            </pre>
          )}
        </div>
      )}

      {/* Share modal */}
      <Modal
        open={shareModal}
        onClose={() => { setShareModal(false); setShareResult(null); setQrUrl(''); }}
        title="Share Credential"
      >
        {!shareResult ? (
          <div className="space-y-4">
            <p className="text-sm text-muted-foreground">
              Create a time-limited public link so a verifier can check this credential.
            </p>
            <div className="grid grid-cols-3 gap-3">
              {[
                { h: 1, label: '1 Hour' },
                { h: 24, label: '24 Hours' },
                { h: 168, label: '7 Days' },
              ].map((opt) => (
                <Button
                  key={opt.h}
                  variant="outline"
                  loading={shareLoading}
                  onClick={() => handleShare(opt.h)}
                >
                  {opt.label}
                </Button>
              ))}
            </div>
            <p className="text-xs text-muted-foreground">
              The link will stop working after the selected period. You can revoke it any time from Shared Links.
            </p>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="rounded-lg bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 p-3">
              <p className="text-xs font-medium text-green-700 dark:text-green-400 mb-0.5">Share link created</p>
              <p className="font-mono text-xs break-all text-green-600 dark:text-green-500">{shareUrl}</p>
            </div>
            {qrUrl && (
              <div className="flex justify-center">
                <img src={qrUrl} alt="QR Code" className="rounded-xl w-48 h-48 border border-border" />
              </div>
            )}
            <div className="flex gap-2">
              <Button className="flex-1" onClick={() => copyLink(shareToken)}>
                <Copy className="h-4 w-4" />Copy Link
              </Button>
              {qrUrl && (
                <Button variant="outline" onClick={() => { setQrModal(true); setShareModal(false); }}>
                  <QrCode className="h-4 w-4" />Full QR
                </Button>
              )}
            </div>
          </div>
        )}
      </Modal>

      {/* QR modal */}
      <Modal open={qrModal} onClose={() => setQrModal(false)} title="Verification QR Code">
        <div className="space-y-4">
          {qrUrl && (
            <div className="flex justify-center">
              <img src={qrUrl} alt="QR Code" className="rounded-xl border border-border" />
            </div>
          )}
          <p className="text-xs text-center text-muted-foreground">
            Scan this code to verify the credential
          </p>
          {shareUrl && (
            <Button className="w-full" variant="outline" onClick={() => copyLink(shareToken)}>
              <Copy className="h-4 w-4" />Copy Link
            </Button>
          )}
        </div>
      </Modal>
    </div>
  );
}

