export default function PresentationPage() {
  const [presentations, setPresentations] = useState([]);
  const [credentials, setCredentials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [createModal, setCreateModal] = useState(false);
  const [creating, setCreating] = useState(false);
  const [expandedId, setExpandedId] = useState(null);

  const [selectedCreds, setSelectedCreds] = useState([]);
  const [purpose, setPurpose] = useState('');
  const [verifierDid, setVerifierDid] = useState('');

  useEffect(() => {
    Promise.allSettled([
      getPresentations(),
      getHolderCredentials({ status: 'active', page_size: 50 }),
    ]).then(([presRes, credsRes]) => {
      if (presRes.status === 'fulfilled') {
        setPresentations(presRes.value.data?.results || presRes.value.data || []);
      }
      if (credsRes.status === 'fulfilled') {
        const d = credsRes.value.data;
        setCredentials(d?.results || d || []);
      }
    }).finally(() => setLoading(false));
  }, []);

  const toggleCred = (id) => {
    setSelectedCreds((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
    );
  };

  const handleCreate = async () => {
    if (selectedCreds.length === 0) {
      toast.error('Select at least one credential');
      return;
    }
    setCreating(true);
    try {
      const res = await createPresentation({
        credential_ids: selectedCreds,
        purpose: purpose || 'Verification',
        verifier_did: verifierDid || undefined,
      });
      setPresentations((p) => [res.data, ...p]);
      setCreateModal(false);
      setSelectedCreds([]);
      setPurpose('');
      setVerifierDid('');
      toast.success('Presentation created');
    } catch (err) {
      toast.error(err.response?.data?.detail || err.response?.data?.error || 'Failed to create presentation');
    } finally {
      setCreating(false);
    }
  };

  return (
    <div className="space-y-5 max-w-2xl">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Presentations</h1>
          <p className="text-sm text-muted-foreground mt-0.5">
            Verifiable proofs you have created from your credentials.
          </p>
        </div>
        <Button size="sm" onClick={() => setCreateModal(true)}>
          <Plus className="h-4 w-4" />New Presentation
        </Button>
      </div>

      {/* List */}
      {loading ? (
        <div className="space-y-3">
          {[1, 2, 3].map((i) => (
            <div key={i} className="h-16 rounded-xl border border-border bg-card animate-pulse" />
          ))}
        </div>
      ) : presentations.length === 0 ? (
        <div className="rounded-xl border border-border bg-card py-16 text-center">
          <Fingerprint className="h-10 w-10 text-muted-foreground mx-auto mb-3" />
          <h3 className="font-semibold text-foreground text-sm mb-1">No presentations yet</h3>
          <p className="text-sm text-muted-foreground mb-4">
            Create a verifiable presentation to share specific credential data.
          </p>
          <Button size="sm" onClick={() => setCreateModal(true)}>
            <Plus className="h-4 w-4" />Create Presentation
          </Button>
        </div>
      ) : (
        <div className="space-y-3">
          {presentations.map((p) => (
            <PresentationCard
              key={p.id}
              presentation={p}
              isExpanded={expandedId === p.id}
              onExpand={() => setExpandedId(expandedId === p.id ? null : p.id)}
            />
          ))}
        </div>
      )}

      {/* Create modal */}
      <Modal
        open={createModal}
        onClose={() => { setCreateModal(false); setSelectedCreds([]); setPurpose(''); setVerifierDid(''); }}
        title="Create Presentation"
      >
        <div className="space-y-4">
          <p className="text-sm text-muted-foreground">
            Select the credentials to include in this presentation.
          </p>

          {/* Credential selection */}
          <div>
            <p className="text-sm font-medium text-foreground mb-2">Credentials *</p>
            {credentials.length === 0 ? (
              <p className="text-sm text-muted-foreground">No active credentials available.</p>
            ) : (
              <div className="space-y-2 max-h-52 overflow-y-auto pr-1">
                {credentials.map((c) => (
                  <label
                    key={c.id}
                    className={`flex items-center gap-3 rounded-lg border p-3 cursor-pointer transition-colors ${
                      selectedCreds.includes(c.id)
                        ? 'border-primary bg-primary/5'
                        : 'border-border hover:bg-muted/30'
                    }`}
                  >
                    <input
                      type="checkbox"
                      checked={selectedCreds.includes(c.id)}
                      onChange={() => toggleCred(c.id)}
                      className="rounded text-primary"
                    />
                    <div className="min-w-0">
                      <p className="text-sm font-medium text-foreground truncate">
                        {c.credential_type_name || c.type || 'Credential'}
                      </p>
                      <p className="text-xs text-muted-foreground truncate">
                        {c.issuer_name || '—'}
                      </p>
                    </div>
                  </label>
                ))}
              </div>
            )}
          </div>

          {/* Purpose */}
          <div>
            <label className="block text-sm font-medium text-foreground mb-1.5">
              Purpose
            </label>
            <input
              type="text"
              value={purpose}
              onChange={(e) => setPurpose(e.target.value)}
              placeholder="e.g. Employment verification"
              className="w-full rounded-lg border border-border bg-background px-3 py-2 text-sm text-foreground placeholder-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary/50"
            />
          </div>

          {/* Verifier DID (optional) */}
          <div>
            <label className="block text-sm font-medium text-foreground mb-1.5">
              Verifier DID <span className="text-muted-foreground font-normal">(optional)</span>
            </label>
            <input
              type="text"
              value={verifierDid}
              onChange={(e) => setVerifierDid(e.target.value)}
              placeholder="did:key:z6Mk…"
              className="w-full rounded-lg border border-border bg-background px-3 py-2 text-sm text-foreground placeholder-muted-foreground font-mono focus:outline-none focus:ring-2 focus:ring-primary/50"
            />
          </div>

          <div className="flex gap-3 pt-1">
            <Button variant="outline" className="flex-1" onClick={() => setCreateModal(false)}>
              Cancel
            </Button>
            <Button
              className="flex-1"
              loading={creating}
              disabled={selectedCreds.length === 0}
              onClick={handleCreate}
            >
              Create
            </Button>
          </div>
        </div>
      </Modal>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link2, Copy, Eye, Clock, AlertCircle, CheckCircle2, BarChart3 } from 'lucide-react';
import { getShares, disableSharing } from '../../api/holder';
import { formatDateTime, isExpired } from '../../utils/formatDate';
import Button from '../../components/common/Button';
import toast from 'react-hot-toast';

function ShareCard({ share, onRevoke }) {
  const [revoking, setRevoking] = useState(false);
  const expired = isExpired(share.expires_at);
  const token = share.token || share.share_token;
  const shareUrl = `${window.location.origin}/verify/${token}`;

  const copy = () => {
    navigator.clipboard.writeText(shareUrl);
    toast.success('Link copied!');
  };

  const revoke = async () => {
    setRevoking(true);
    try {
      await disableSharing({ credential_id: share.credential_id });
      onRevoke(share.id);
      toast.success('Share link revoked');
    } catch {
      toast.error('Failed to revoke share link');
    } finally {
      setRevoking(false);
    }
  };

  return (
    <div
      className={`rounded-xl border bg-card p-4 transition-opacity ${
        expired ? 'opacity-60 border-border' : 'border-border'
      }`}
    >
      <div className="flex items-start justify-between gap-3">
        <div className="flex-1 min-w-0">
          {/* Credential name */}
          <div className="flex items-center gap-2 mb-1.5">
            <p className="font-medium text-sm text-foreground truncate">
              {share.credential_type_name || share.credential_name || 'Credential'}
            </p>
            {expired ? (
              <span className="inline-flex items-center gap-1 rounded-full bg-yellow-100 dark:bg-yellow-900/30 px-2 py-0.5 text-[10px] font-medium text-yellow-700 dark:text-yellow-400">
                <Clock className="h-3 w-3" />Expired
              </span>
            ) : (
              <span className="inline-flex items-center gap-1 rounded-full bg-green-100 dark:bg-green-900/30 px-2 py-0.5 text-[10px] font-medium text-green-700 dark:text-green-400">
                <CheckCircle2 className="h-3 w-3" />Active
              </span>
            )}
          </div>

          {/* Token */}
          <p className="text-xs text-muted-foreground font-mono truncate mb-2">
            {token}
          </p>

          {/* Meta row */}
          <div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground">
            <span className="flex items-center gap-1">
              <Eye className="h-3 w-3" />
              {share.access_count || 0} view{share.access_count !== 1 ? 's' : ''}
            </span>
            {share.expires_at && (
              <span className="flex items-center gap-1">
                <Clock className="h-3 w-3" />
                {expired ? 'Expired' : 'Expires'}: {formatDateTime(share.expires_at)}
              </span>
            )}
          </div>
        </div>

        {/* Actions */}
        <div className="flex items-center gap-1 shrink-0">
          {!expired && (
            <Button
              size="icon"
              variant="ghost"
              onClick={copy}
              title="Copy link"
              className="h-8 w-8"
            >
              <Copy className="h-3.5 w-3.5 text-muted-foreground" />
            </Button>
          )}
          <Button
            size="sm"
            variant="ghost"
            loading={revoking}
            onClick={revoke}
            className="text-red-600 hover:text-red-700 hover:bg-red-50 dark:hover:bg-red-900/20 h-8 px-2"
            title="Revoke"
          >
            Revoke
          </Button>
        </div>
      </div>
    </div>
  );
}

export default function SharesPage() {
  const [shares, setShares] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getShares()
      .then((r) => setShares(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const handleRevoke = (id) => {
    setShares((s) => s.filter((x) => x.id !== id));
  };

  const active = shares.filter((s) => !isExpired(s.expires_at)).length;
  const expired = shares.length - active;

  return (
    <div className="space-y-5 max-w-2xl">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-foreground">Shared Links</h1>
        <p className="text-sm text-muted-foreground mt-0.5">
          Manage public links for your shared credentials.
        </p>
      </div>

      {/* Stats */}
      {!loading && shares.length > 0 && (
        <div className="flex gap-4 rounded-xl border border-border bg-card p-4">
          <div className="flex items-center gap-2">
            <BarChart3 className="h-4 w-4 text-muted-foreground" />
            <span className="text-sm text-muted-foreground">
              <strong className="text-foreground">{active}</strong> active,{' '}
              <strong className="text-foreground">{expired}</strong> expired
            </span>
          </div>
        </div>
      )}

      {/* Info box */}
      <div className="rounded-lg bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 p-3 flex items-start gap-2">
        <AlertCircle className="h-4 w-4 text-blue-600 dark:text-blue-400 shrink-0 mt-0.5" />
        <p className="text-xs text-blue-700 dark:text-blue-300">
          Share links let anyone with the link view your credential. Create them from a credential's detail page and revoke any time.
        </p>
      </div>

      {/* List */}
      {loading ? (
        <div className="space-y-3">
          {[1, 2, 3].map((i) => (
            <div key={i} className="h-24 rounded-xl border border-border bg-card animate-pulse" />
          ))}
        </div>
      ) : shares.length === 0 ? (
        <div className="rounded-xl border border-border bg-card py-16 text-center">
          <Link2 className="h-8 w-8 text-muted-foreground mx-auto mb-3" />
          <p className="font-medium text-foreground text-sm mb-1">No shared links yet</p>
          <p className="text-sm text-muted-foreground">
            Open a credential and click <strong>Share</strong> to create a link.
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {shares.map((s) => (
            <ShareCard key={s.id} share={s} onRevoke={handleRevoke} />
          ))}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { useAuth } from '../../context/AuthContext';
import useAuthStore from '../../store/authStore';
import { changePassword, getMe } from '../../api/auth';
import { getWallets } from '../../api/holder';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import toast from 'react-hot-toast';
import {
  User, Lock, Key, CreditCard, ShieldCheck, Copy,
  Fingerprint, Phone, Mail, Calendar,
} from 'lucide-react';

function Section({ title, icon: Icon, children }) {
  return (
    <div className="rounded-xl border border-border bg-card overflow-hidden">
      <div className="flex items-center gap-2 px-5 py-4 border-b border-border">
        <Icon className="h-4 w-4 text-muted-foreground" />
        <h2 className="font-semibold text-foreground text-sm">{title}</h2>
      </div>
      <div className="p-5">{children}</div>
    </div>
  );
}

function InfoRow({ label, value, mono = false, copyable = false }) {
  const copy = () => {
    navigator.clipboard.writeText(String(value));
    toast.success('Copied!');
  };
  return (
    <div className="flex items-center justify-between py-2.5 gap-4">
      <dt className="text-sm text-muted-foreground shrink-0">{label}</dt>
      <dd className={`flex items-center gap-2 text-sm font-medium text-foreground text-right ${mono ? 'font-mono text-xs' : ''}`}>
        <span className="truncate max-w-xs">{value || '—'}</span>
        {copyable && value && (
          <button onClick={copy} className="shrink-0 p-0.5 text-muted-foreground hover:text-foreground transition-colors">
            <Copy className="h-3.5 w-3.5" />
          </button>
        )}
      </dd>
    </div>
  );
}

export default function HolderSettings() {
  const { user: ctxUser } = useAuth();
  const { user: storeUser } = useAuthStore();
  const user = ctxUser || storeUser;

  const [pwLoading, setPwLoading] = useState(false);
  const [wallets, setWallets] = useState([]);

  const { register, handleSubmit, reset, watch, formState: { errors } } = useForm();

  useEffect(() => {
    getWallets()
      .then((r) => setWallets(r.data?.results || r.data || []))
      .catch(() => {});
  }, []);

  const onPwSubmit = async (data) => {
    setPwLoading(true);
    try {
      await changePassword({ old_password: data.old_password, new_password: data.new_password });
      toast.success('Password updated successfully');
      reset();
    } catch (err) {
      const msg = err.response?.data?.detail
        || Object.values(err.response?.data || {})[0]?.[0]
        || 'Failed to update password';
      toast.error(msg);
    } finally {
      setPwLoading(false);
    }
  };

  const identity = user?.identity;
  const did = user?.did || identity?.did || '';

  return (
    <div className="max-w-lg space-y-5">
      <div>
        <h1 className="text-2xl font-bold text-foreground">Settings</h1>
        <p className="text-sm text-muted-foreground mt-0.5">Manage your identity and wallet preferences.</p>
      </div>

      {/* Identity badge */}
      {user?.national_id_verified && (
        <div className="flex items-center gap-2 rounded-lg bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 px-4 py-3">
          <ShieldCheck className="h-4 w-4 text-green-600 dark:text-green-400 shrink-0" />
          <p className="text-sm font-medium text-green-700 dark:text-green-400">
            National Identity Verified
          </p>
        </div>
      )}

      {/* Profile */}
      <Section title="Profile" icon={User}>
        <dl className="divide-y divide-border">
          <InfoRow
            label="Full Name"
            value={
              identity?.full_name
              || (user?.first_name ? `${user.first_name} ${user.last_name || ''}`.trim() : null)
            }
          />
          <InfoRow label="Email" value={user?.email} icon={Mail} />
          <InfoRow label="Phone" value={user?.phone_number || identity?.phone} icon={Phone} />
          <InfoRow label="National ID" value={user?.national_id} />
          {identity?.dob && <InfoRow label="Date of Birth" value={identity.dob} />}
          {identity?.gender && <InfoRow label="Gender" value={identity.gender} />}
          {identity?.address && <InfoRow label="Address" value={identity.address} />}
          <InfoRow label="Role" value={user?.role ? user.role.charAt(0).toUpperCase() + user.role.slice(1) : 'Holder'} />
        </dl>
      </Section>

      {/* DID */}
      {did && (
        <Section title="Decentralized Identifier (DID)" icon={Fingerprint}>
          <div className="space-y-3">
            <div className="rounded-lg bg-muted/50 px-3 py-2.5">
              <p className="text-[10px] text-muted-foreground uppercase tracking-wide mb-1">Your DID</p>
              <div className="flex items-center gap-2">
                <p className="font-mono text-xs text-foreground flex-1 break-all">{did}</p>
                <button
                  onClick={() => { navigator.clipboard.writeText(did); toast.success('DID copied!'); }}
                  className="shrink-0 p-1 text-muted-foreground hover:text-foreground transition-colors rounded"
                >
                  <Copy className="h-3.5 w-3.5" />
                </button>
              </div>
            </div>
            <p className="text-xs text-muted-foreground">
              Your DID is a globally unique identifier anchored to your verified identity.
              It is used to cryptographically sign and receive verifiable credentials.
            </p>
          </div>
        </Section>
      )}

      {/* Wallets */}
      {wallets.length > 0 && (
        <Section title="Wallets" icon={CreditCard}>
          <div className="space-y-2">
            {wallets.map((w) => (
              <div key={w.id} className="flex items-center justify-between rounded-lg border border-border p-3">
                <div>
                  <p className="text-sm font-medium text-foreground">{w.wallet_name}</p>
                  <p className="text-xs text-muted-foreground mt-0.5">
                    {w.is_active ? 'Active' : 'Inactive'} · {w.device_id || 'Default device'}
                  </p>
                </div>
                {w.is_active && (
                  <span className="rounded-full bg-green-100 dark:bg-green-900/30 px-2 py-0.5 text-[10px] font-medium text-green-700 dark:text-green-400">
                    Active
                  </span>
                )}
              </div>
            ))}
          </div>
        </Section>
      )}

      {/* Change Password */}
      <Section title="Change Password" icon={Lock}>
        <form onSubmit={handleSubmit(onPwSubmit)} className="space-y-4">
          <Input
            label="Current Password"
            type="password"
            autoComplete="current-password"
            error={errors.old_password?.message}
            {...register('old_password', { required: 'Current password is required' })}
          />
          <Input
            label="New Password"
            type="password"
            autoComplete="new-password"
            error={errors.new_password?.message}
            {...register('new_password', {
              required: 'New password is required',
              minLength: { value: 8, message: 'At least 8 characters' },
            })}
          />
          <Input
            label="Confirm New Password"
            type="password"
            autoComplete="new-password"
            error={errors.confirm?.message}
            {...register('confirm', {
              required: 'Please confirm your password',
              validate: (v) => v === watch('new_password') || 'Passwords do not match',
            })}
          />
          <Button type="submit" loading={pwLoading}>Update Password</Button>
        </form>
      </Section>

      {/* Account info */}
      <Section title="Account Info" icon={Key}>
        <dl className="divide-y divide-border">
          <InfoRow label="Account ID" value={user?.id} mono copyable />
          <InfoRow label="Status" value={user?.user_status === 'active' ? 'Active' : user?.user_status || 'Active'} />
          <InfoRow label="National ID Verified" value={user?.national_id_verified ? 'Yes' : 'No'} />
        </dl>
      </Section>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { CreditCard, Search, CheckCircle2, ArrowRight, Building2 } from 'lucide-react';
import { getRequestCatalog, createHolderRequest } from '../../api/holder';
import Textarea from '../../components/common/Textarea';
import Button from '../../components/common/Button';
import toast from 'react-hot-toast';

export default function RequestCredentialPage() {
  const navigate = useNavigate();
  const [credTypes, setCredTypes] = useState([]);
  const [loading, setLoading] = useState(false);
  const [catalogLoading, setCatalogLoading] = useState(true);
  const [selected, setSelected] = useState(null);
  const [search, setSearch] = useState('');
  const { register, handleSubmit, formState: { errors } } = useForm();

  useEffect(() => {
    getRequestCatalog()
      .then((r) => setCredTypes(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setCatalogLoading(false));
  }, []);

  const filtered = credTypes.filter((t) =>
    !search || t.name?.toLowerCase().includes(search.toLowerCase()) ||
    t.description?.toLowerCase().includes(search.toLowerCase()) ||
    t.organization_name?.toLowerCase().includes(search.toLowerCase())
  );

  const onSubmit = async (data) => {
    if (!selected) {
      toast.error('Please select a credential type');
      return;
    }
    setLoading(true);
    try {
      await createHolderRequest({
        credential_type: selected.id,
        organization: selected.organization_id,
        message: data.message || '',
      });
      toast.success('Credential request submitted successfully');
      navigate('/holder/requests');
    } catch (err) {
      const msg = err.response?.data?.detail
        || Object.values(err.response?.data || {})[0]?.[0]
        || 'Failed to submit request';
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-5">
      <div>
        <h1 className="text-2xl font-bold text-foreground">Request a Credential</h1>
        <p className="text-muted-foreground text-sm mt-0.5">
          Browse available credentials and submit a request to an issuer.
        </p>
      </div>

      {/* Step indicator */}
      <div className="flex items-center gap-2">
        {['Choose Credential', 'Add Details', 'Submit'].map((s, i) => {
          const step = selected ? (i < 2 ? 'done' : 'active') : (i === 0 ? 'active' : 'future');
          return (
            <div key={s} className="flex items-center gap-2 flex-1">
              <div className={`flex h-6 w-6 shrink-0 items-center justify-center rounded-full text-xs font-bold ${
                step === 'done' ? 'bg-primary text-primary-foreground' :
                step === 'active' ? 'bg-primary text-primary-foreground' :
                'bg-muted text-muted-foreground'
              }`}>
                {step === 'done' ? '✓' : i + 1}
              </div>
              <span className={`text-xs ${step === 'active' ? 'text-foreground font-medium' : 'text-muted-foreground'}`}>
                {s}
              </span>
              {i < 2 && <div className={`flex-1 h-px ${step === 'done' ? 'bg-primary' : 'bg-border'}`} />}
            </div>
          );
        })}
      </div>

      {/* Credential catalog */}
      <div className="rounded-xl border border-border bg-card p-5 space-y-4">
        <div className="flex items-center justify-between">
          <h2 className="font-semibold text-foreground text-sm">Available Credentials</h2>
          {selected && (
            <button
              onClick={() => setSelected(null)}
              className="text-xs text-muted-foreground hover:text-foreground"
            >
              Change selection
            </button>
          )}
        </div>

        {/* Search */}
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search credential types…"
            className="w-full rounded-lg border border-border bg-background pl-9 pr-3 py-2 text-sm text-foreground placeholder-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary/50"
          />
        </div>

        {/* Grid */}
        {catalogLoading ? (
          <div className="grid sm:grid-cols-2 gap-3">
            {[1, 2, 3, 4].map((i) => (
              <div key={i} className="h-20 rounded-lg bg-muted/50 animate-pulse" />
            ))}
          </div>
        ) : filtered.length === 0 ? (
          <div className="py-8 text-center">
            <CreditCard className="h-8 w-8 text-muted-foreground mx-auto mb-2" />
            <p className="text-sm text-muted-foreground">
              {search ? 'No credential types match your search.' : 'No credential types available.'}
            </p>
          </div>
        ) : (
          <div className="grid sm:grid-cols-2 gap-3 max-h-72 overflow-y-auto pr-1">
            {filtered.map((t) => {
              const isSelected = selected?.id === t.id;
              return (
                <button
                  key={t.id}
                  onClick={() => setSelected(t)}
                  className={`flex items-start gap-3 rounded-lg border p-3.5 text-left transition-all ${
                    isSelected
                      ? 'border-primary bg-primary/5 shadow-sm'
                      : 'border-border hover:border-primary/40 hover:bg-muted/30'
                  }`}
                >
                  <div className={`rounded-lg p-2 shrink-0 mt-0.5 ${isSelected ? 'bg-primary/20' : 'bg-muted'}`}>
                    <CreditCard className={`h-4 w-4 ${isSelected ? 'text-primary' : 'text-muted-foreground'}`} />
                  </div>
                  <div className="min-w-0 flex-1">
                    <div className="flex items-center justify-between gap-2">
                      <p className="font-medium text-sm text-foreground truncate">{t.name}</p>
                      {isSelected && <CheckCircle2 className="h-4 w-4 text-primary shrink-0" />}
                    </div>
                    {t.organization_name && (
                      <div className="flex items-center gap-1 mt-0.5">
                        <Building2 className="h-3 w-3 text-muted-foreground" />
                        <p className="text-xs text-muted-foreground truncate">{t.organization_name}</p>
                      </div>
                    )}
                    {t.description && (
                      <p className="text-xs text-muted-foreground mt-1 line-clamp-2">{t.description}</p>
                    )}
                  </div>
                </button>
              );
            })}
          </div>
        )}

        {/* Selected preview */}
        {selected && (
          <div className="rounded-lg bg-primary/5 border border-primary/20 px-4 py-3 flex items-center gap-3">
            <CheckCircle2 className="h-4 w-4 text-primary shrink-0" />
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-foreground">{selected.name}</p>
              {selected.organization_name && (
                <p className="text-xs text-muted-foreground">{selected.organization_name}</p>
              )}
            </div>
          </div>
        )}
      </div>

      {/* Form (visible once type selected) */}
      {selected && (
        <div className="rounded-xl border border-border bg-card p-5">
          <h2 className="font-semibold text-foreground text-sm mb-4">Request Details</h2>
          <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
            <Textarea
              label="Message to Issuer"
              placeholder="Provide any additional context or documents reference…"
              rows={4}
              hint="Optional — add any relevant information the issuer may need."
              {...register('message')}
            />
            <div className="flex gap-3">
              <Button type="button" variant="outline" onClick={() => navigate(-1)}>
                Cancel
              </Button>
              <Button type="submit" loading={loading} className="flex-1">
                <ArrowRight className="h-4 w-4" />Submit Request
              </Button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { ClipboardList, Plus, Clock, CheckCircle2, XCircle, Package } from 'lucide-react';
import { getHolderRequests } from '../../api/holder';
import { StatusBadge } from '../../components/common/Badge';
import Button from '../../components/common/Button';
import { formatDate, formatRelative } from '../../utils/formatDate';

const STATUS_ICON = {
  pending: Clock,
  approved: CheckCircle2,
  issued: Package,
  rejected: XCircle,
};

const STATUS_COLOR = {
  pending: 'text-yellow-600 bg-yellow-50 dark:bg-yellow-900/20',
  approved: 'text-green-600 bg-green-50 dark:bg-green-900/20',
  issued: 'text-blue-600 bg-blue-50 dark:bg-blue-900/20',
  rejected: 'text-red-600 bg-red-50 dark:bg-red-900/20',
};

export default function HolderRequestsPage() {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('');

  useEffect(() => {
    getHolderRequests()
      .then((r) => setRequests(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const filtered = filter ? requests.filter((r) => r.status === filter) : requests;

  const tabs = [
    { key: '', label: 'All', count: requests.length },
    { key: 'pending', label: 'Pending', count: requests.filter((r) => r.status === 'pending').length },
    { key: 'approved', label: 'Approved', count: requests.filter((r) => r.status === 'approved').length },
    { key: 'issued', label: 'Issued', count: requests.filter((r) => r.status === 'issued').length },
    { key: 'rejected', label: 'Rejected', count: requests.filter((r) => r.status === 'rejected').length },
  ];

  return (
    <div className="space-y-5 max-w-2xl">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">My Requests</h1>
          <p className="text-sm text-muted-foreground mt-0.5">Track your credential requests.</p>
        </div>
        <Link to="/holder/credentials/request">
          <Button size="sm"><Plus className="h-4 w-4" />New Request</Button>
        </Link>
      </div>

      {/* Status tabs */}
      <div className="flex gap-1 rounded-xl bg-muted/50 p-1 overflow-x-auto">
        {tabs.map((t) => (
          <button
            key={t.key}
            onClick={() => setFilter(t.key)}
            className={`flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-sm font-medium whitespace-nowrap transition-all ${
              filter === t.key
                ? 'bg-card text-foreground shadow-sm'
                : 'text-muted-foreground hover:text-foreground'
            }`}
          >
            {t.label}
            {t.count > 0 && (
              <span className={`rounded-full px-1.5 py-0.5 text-[10px] font-bold ${
                filter === t.key ? 'bg-primary/10 text-primary' : 'bg-muted text-muted-foreground'
              }`}>
                {t.count}
              </span>
            )}
          </button>
        ))}
      </div>

      {/* List */}
      {loading ? (
        <div className="space-y-3">
          {[1, 2, 3].map((i) => (
            <div key={i} className="h-20 rounded-xl border border-border bg-card animate-pulse" />
          ))}
        </div>
      ) : filtered.length === 0 ? (
        <div className="rounded-xl border border-border bg-card py-16 text-center">
          <ClipboardList className="h-8 w-8 text-muted-foreground mx-auto mb-3" />
          <p className="font-medium text-foreground text-sm mb-1">No requests</p>
          <p className="text-sm text-muted-foreground mb-4">
            {filter ? `No ${filter} requests found.` : "You haven't made any credential requests yet."}
          </p>
          <Link to="/holder/credentials/request">
            <Button size="sm"><Plus className="h-4 w-4" />Request a Credential</Button>
          </Link>
        </div>
      ) : (
        <div className="space-y-3">
          {filtered.map((req) => {
            const StatusIcon = STATUS_ICON[req.status] || Clock;
            const colorClass = STATUS_COLOR[req.status] || 'text-muted-foreground bg-muted';
            return (
              <div key={req.id} className="rounded-xl border border-border bg-card p-4">
                <div className="flex items-start gap-3">
                  <div className={`rounded-lg p-2 shrink-0 mt-0.5 ${colorClass}`}>
                    <StatusIcon className="h-4 w-4" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between gap-2 mb-1">
                      <p className="font-medium text-sm text-foreground truncate">
                        {req.credential_type_name || req.credential_type || 'Credential Request'}
                      </p>
                      <StatusBadge status={req.status} />
                    </div>
                    {(req.organization_name || req.issuer_name) && (
                      <p className="text-xs text-muted-foreground mb-1">
                        Issuer: {req.organization_name || req.issuer_name}
                      </p>
                    )}
                    <div className="flex items-center gap-3 text-xs text-muted-foreground">
                      <span>Requested {formatRelative(req.created_at)}</span>
                      {req.updated_at !== req.created_at && (
                        <span>Updated {formatRelative(req.updated_at)}</span>
                      )}
                    </div>
                    {req.status === 'rejected' && req.rejection_reason && (
                      <div className="mt-2 rounded-md bg-red-50 dark:bg-red-900/20 px-3 py-2">
                        <p className="text-xs text-red-600 dark:text-red-400">
                          Reason: {req.rejection_reason}
                        </p>
                      </div>
                    )}
                    {req.status === 'issued' && req.credential_id && (
                      <Link
                        to={`/holder/credentials/${req.credential_id}`}
                        className="inline-flex items-center gap-1 mt-2 text-xs text-primary hover:underline"
                      >
                        View credential →
                      </Link>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Activity, CheckCircle2, XCircle, Shield, Calendar } from 'lucide-react';
import { getHolderVerificationHistory } from '../../api/holder';
import { formatDateTime, formatRelative } from '../../utils/formatDate';

export default function HolderVerificationHistory() {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    getHolderVerificationHistory()
      .then((r) => setHistory(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const filtered = filter === 'all' ? history
    : filter === 'valid' ? history.filter((h) => h.is_valid)
    : history.filter((h) => !h.is_valid);

  const total = history.length;
  const valid = history.filter((h) => h.is_valid).length;
  const invalid = total - valid;

  return (
    <div className="space-y-5 max-w-2xl">
      <div>
        <h1 className="text-2xl font-bold text-foreground">Verification History</h1>
        <p className="text-sm text-muted-foreground mt-0.5">
          A log of when your credentials were verified by third parties.
        </p>
      </div>

      {/* Summary cards */}
      {!loading && total > 0 && (
        <div className="grid grid-cols-3 gap-3">
          {[
            { label: 'Total Verifications', value: total, icon: Activity, color: 'text-blue-600', bg: 'bg-blue-50 dark:bg-blue-900/20' },
            { label: 'Successful', value: valid, icon: CheckCircle2, color: 'text-green-600', bg: 'bg-green-50 dark:bg-green-900/20' },
            { label: 'Failed', value: invalid, icon: XCircle, color: 'text-red-600', bg: 'bg-red-50 dark:bg-red-900/20' },
          ].map((s) => (
            <div key={s.label} className="rounded-xl border border-border bg-card p-4">
              <div className="flex items-center justify-between mb-2">
                <span className="text-xs text-muted-foreground">{s.label}</span>
                <div className={`rounded-lg p-1.5 ${s.bg}`}>
                  <s.icon className={`h-3.5 w-3.5 ${s.color}`} />
                </div>
              </div>
              <p className="text-2xl font-bold text-foreground">{s.value}</p>
            </div>
          ))}
        </div>
      )}

      {/* Filter tabs */}
      <div className="flex gap-1 rounded-xl bg-muted/50 p-1 w-fit">
        {[
          { key: 'all', label: 'All' },
          { key: 'valid', label: 'Successful' },
          { key: 'invalid', label: 'Failed' },
        ].map((t) => (
          <button
            key={t.key}
            onClick={() => setFilter(t.key)}
            className={`rounded-lg px-3 py-1.5 text-sm font-medium transition-all ${
              filter === t.key
                ? 'bg-card text-foreground shadow-sm'
                : 'text-muted-foreground hover:text-foreground'
            }`}
          >
            {t.label}
          </button>
        ))}
      </div>

      {/* List */}
      {loading ? (
        <div className="space-y-3">
          {[1, 2, 3, 4].map((i) => (
            <div key={i} className="h-20 rounded-xl border border-border bg-card animate-pulse" />
          ))}
        </div>
      ) : filtered.length === 0 ? (
        <div className="rounded-xl border border-border bg-card py-16 text-center">
          <Shield className="h-8 w-8 text-muted-foreground mx-auto mb-3" />
          <p className="font-medium text-foreground text-sm mb-1">No verifications yet</p>
          <p className="text-sm text-muted-foreground">
            {filter === 'all'
              ? 'Your credential verification history will appear here.'
              : `No ${filter === 'valid' ? 'successful' : 'failed'} verifications found.`}
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {filtered.map((v, idx) => (
            <div key={v.id || idx} className="rounded-xl border border-border bg-card p-4">
              <div className="flex items-start gap-3">
                <div className={`rounded-lg p-2 shrink-0 mt-0.5 ${
                  v.is_valid
                    ? 'bg-green-50 dark:bg-green-900/20'
                    : 'bg-red-50 dark:bg-red-900/20'
                }`}>
                  {v.is_valid
                    ? <CheckCircle2 className="h-4 w-4 text-green-600" />
                    : <XCircle className="h-4 w-4 text-red-600" />}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-start justify-between gap-2 mb-0.5">
                    <p className="font-medium text-sm text-foreground truncate">
                      {v.credential_type || v.credential_type_name || 'Credential'}
                    </p>
                    <span className={`shrink-0 text-xs font-medium ${v.is_valid ? 'text-green-600' : 'text-red-600'}`}>
                      {v.is_valid ? 'Valid' : 'Failed'}
                    </span>
                  </div>
                  {v.verifier_name && (
                    <p className="text-xs text-muted-foreground mb-1">
                      Verified by: {v.verifier_name}
                    </p>
                  )}
                  <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                    <Calendar className="h-3 w-3" />
                    <span>{formatDateTime(v.verified_at || v.created_at)}</span>
                    <span className="text-muted-foreground/50">·</span>
                    <span>{formatRelative(v.verified_at || v.created_at)}</span>
                  </div>
                  {v.verification_method && (
                    <span className="inline-block mt-1.5 rounded-full bg-muted px-2 py-0.5 text-[10px] font-medium text-muted-foreground">
                      {v.verification_method}
                    </span>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Bell, Check, Trash2, BellOff, Info, AlertCircle, CheckCircle2 } from 'lucide-react';
import {
  getHolderNotifications,
  markHolderNotificationRead,
  markAllHolderNotificationsRead,
  deleteHolderNotification,
} from '../../api/holder';
import { formatRelative, formatDateTime } from '../../utils/formatDate';
import Button from '../../components/common/Button';
import toast from 'react-hot-toast';

const NOTIF_ICON = {
  info: Info,
  success: CheckCircle2,
  warning: AlertCircle,
  error: AlertCircle,
};

const NOTIF_COLOR = {
  info: 'text-blue-600',
  success: 'text-green-600',
  warning: 'text-yellow-600',
  error: 'text-red-600',
};

function NotificationItem({ item, onMarkRead, onDelete }) {
  const notif = item.notification || item;
  const isRead = item.is_read || item.status === 'read';
  const type = notif.notification_type || 'info';
  const Icon = NOTIF_ICON[type] || Bell;
  const iconColor = NOTIF_COLOR[type] || 'text-muted-foreground';

  return (
    <div
      className={`flex items-start gap-3 rounded-xl border p-4 transition-colors ${
        !isRead ? 'border-primary/20 bg-primary/5' : 'border-border bg-card'
      }`}
    >
      <div className={`mt-0.5 shrink-0 ${iconColor}`}>
        <Icon className="h-4 w-4" />
      </div>
      <div className="flex-1 min-w-0">
        <div className="flex items-start justify-between gap-3">
          <div className="min-w-0 flex-1">
            <p className={`text-sm ${!isRead ? 'font-semibold text-foreground' : 'font-medium text-foreground'} truncate`}>
              {notif.title || notif.message || 'Notification'}
            </p>
            {notif.body && (
              <p className="text-xs text-muted-foreground mt-0.5 line-clamp-2">{notif.body}</p>
            )}
            <p className="text-xs text-muted-foreground mt-1.5" title={formatDateTime(notif.created_at || item.created_at)}>
              {formatRelative(notif.created_at || item.created_at)}
            </p>
          </div>
          <div className="flex items-center gap-1 shrink-0">
            {!isRead && (
              <Button
                size="icon"
                variant="ghost"
                onClick={() => onMarkRead(item.id)}
                title="Mark as read"
                className="h-7 w-7"
              >
                <Check className="h-3.5 w-3.5 text-muted-foreground" />
              </Button>
            )}
            <Button
              size="icon"
              variant="ghost"
              onClick={() => onDelete(item.id)}
              title="Delete"
              className="h-7 w-7"
            >
              <Trash2 className="h-3.5 w-3.5 text-muted-foreground hover:text-red-600" />
            </Button>
          </div>
        </div>
      </div>
      {!isRead && (
        <div className="mt-1.5 h-2 w-2 shrink-0 rounded-full bg-primary" />
      )}
    </div>
  );
}

export default function HolderNotifications() {
  const [notifications, setNotifications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  const load = () => {
    setLoading(true);
    getHolderNotifications({ limit: 50 })
      .then((r) => setNotifications(r.data?.results || r.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, []);

  const markRead = async (id) => {
    try {
      await markHolderNotificationRead(id);
      setNotifications((n) =>
        n.map((x) => x.id === id ? { ...x, is_read: true, status: 'read' } : x)
      );
    } catch {
      toast.error('Failed to mark as read');
    }
  };

  const markAll = async () => {
    try {
      await markAllHolderNotificationsRead();
      setNotifications((n) => n.map((x) => ({ ...x, is_read: true, status: 'read' })));
      toast.success('All notifications marked as read');
    } catch {
      toast.error('Failed to mark all as read');
    }
  };

  const remove = async (id) => {
    try {
      await deleteHolderNotification(id);
      setNotifications((n) => n.filter((x) => x.id !== id));
    } catch {
      toast.error('Failed to delete notification');
    }
  };

  const unread = notifications.filter((n) => !n.is_read && n.status !== 'read').length;
  const filtered = filter === 'unread'
    ? notifications.filter((n) => !n.is_read && n.status !== 'read')
    : notifications;

  return (
    <div className="space-y-5 max-w-2xl">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Notifications</h1>
          <p className="text-sm text-muted-foreground mt-0.5">
            {unread > 0 ? `${unread} unread notification${unread !== 1 ? 's' : ''}` : 'All caught up!'}
          </p>
        </div>
        {unread > 0 && (
          <Button size="sm" variant="outline" onClick={markAll}>
            <Check className="h-4 w-4" />Mark all read
          </Button>
        )}
      </div>

      {/* Filter tabs */}
      <div className="flex gap-1 rounded-xl bg-muted/50 p-1 w-fit">
        {[
          { key: 'all', label: `All (${notifications.length})` },
          { key: 'unread', label: `Unread (${unread})` },
        ].map((t) => (
          <button
            key={t.key}
            onClick={() => setFilter(t.key)}
            className={`rounded-lg px-3 py-1.5 text-sm font-medium transition-all ${
              filter === t.key
                ? 'bg-card text-foreground shadow-sm'
                : 'text-muted-foreground hover:text-foreground'
            }`}
          >
            {t.label}
          </button>
        ))}
      </div>

      {/* List */}
      {loading ? (
        <div className="space-y-3">
          {[1, 2, 3].map((i) => (
            <div key={i} className="h-20 rounded-xl border border-border bg-card animate-pulse" />
          ))}
        </div>
      ) : filtered.length === 0 ? (
        <div className="rounded-xl border border-border bg-card py-16 text-center">
          <BellOff className="h-8 w-8 text-muted-foreground mx-auto mb-3" />
          <p className="font-medium text-foreground text-sm mb-1">
            {filter === 'unread' ? 'No unread notifications' : 'No notifications'}
          </p>
          <p className="text-sm text-muted-foreground">
            {filter === 'unread'
              ? "You've read everything!"
              : "Notifications about your credentials will appear here."}
          </p>
        </div>
      ) : (
        <div className="space-y-2">
          {filtered.map((n) => (
            <NotificationItem
              key={n.id}
              item={n}
              onMarkRead={markRead}
              onDelete={remove}
            />
          ))}
        </div>
      )}
    </div>
  );
}
